INSERT INTO frameworks (id, organization_id, name, description) VALUES ('3ae7e475-dd51-45e7-a79a-1c159fbf6abc', NULL, 'MÜDEK v3.1', 'MÜDEK engineering accreditation framework — 18 programme outcomes (PO 1.1–11)') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('30c90baa-2480-491f-a801-7ce273391fb5', '3ae7e475-dd51-45e7-a79a-1c159fbf6abc', 'PO 1.1', 'Foundational Knowledge', 'Knowledge in mathematics, natural sciences, basic engineering, computational methods, and discipline-specific topics', 1) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('3ee62349-8163-4db2-a144-9b62374311d4', '3ae7e475-dd51-45e7-a79a-1c159fbf6abc', 'PO 1.2', 'Knowledge Application', 'Ability to apply knowledge in mathematics, natural sciences, basic engineering, computational methods, and discipline-specific topics to solve complex engineering problems', 2) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('aea8cfb1-6f88-40a1-a118-a776e042c6f2', '3ae7e475-dd51-45e7-a79a-1c159fbf6abc', 'PO 2', 'Problem Identification & Analysis', 'Ability to identify, formulate, and analyze complex engineering problems using basic science, mathematics, and engineering knowledge while considering relevant UN Sustainable Development Goals', 3) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('f720ef82-6b50-4313-a04f-260164468056', '3ae7e475-dd51-45e7-a79a-1c159fbf6abc', 'PO 3.1', 'Creative Solution Design', 'Ability to design creative solutions to complex engineering problems', 4) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('d2e89af7-f927-4e15-a8b5-f1274a2588de', '3ae7e475-dd51-45e7-a79a-1c159fbf6abc', 'PO 3.2', 'Complex System Design', 'Ability to design complex systems, processes, devices, or products that meet current and future requirements while considering realistic constraints and conditions', 5) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('ac219cc6-98f2-4370-ac02-b6be93a973f3', '3ae7e475-dd51-45e7-a79a-1c159fbf6abc', 'PO 4', 'Modern Tools & Techniques', 'Ability to select and use appropriate techniques, resources, and modern engineering and IT tools, including estimation and modeling, for analysis and solution of complex engineering problems, with awareness of their limitations', 6) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('bf0b0958-fe24-4250-a73b-8765aa1d3fa4', '3ae7e475-dd51-45e7-a79a-1c159fbf6abc', 'PO 5', 'Research Methods', 'Ability to use research methods including literature review, experiment design, data collection, result analysis, and interpretation for investigation of complex engineering problems', 7) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('6b2cfa24-8ab4-4d52-ae05-e2074320b359', '3ae7e475-dd51-45e7-a79a-1c159fbf6abc', 'PO 6.1', 'Societal & Environmental Impact', 'Knowledge of the impacts of engineering applications on society, health and safety, economy, sustainability, and environment within the scope of UN Sustainable Development Goals', 8) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('5777b8bf-6357-4724-afe0-3645980f0b98', '3ae7e475-dd51-45e7-a79a-1c159fbf6abc', 'PO 6.2', 'Legal Awareness', 'Awareness of the legal consequences of engineering solutions', 9) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('76e9cbfc-2fc6-4174-aed9-ddae8911cad9', '3ae7e475-dd51-45e7-a79a-1c159fbf6abc', 'PO 7.1', 'Ethics & Professional Conduct', 'Knowledge of acting in accordance with engineering professional principles and ethical responsibility', 10) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('8554c4a4-772f-442d-a894-c87a8a5c6f9c', '3ae7e475-dd51-45e7-a79a-1c159fbf6abc', 'PO 7.2', 'Impartiality & Diversity', 'Awareness of acting without discrimination and being inclusive of diversity', 11) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('f7f015bf-456b-4a74-a6e6-ab6ff35a527a', '3ae7e475-dd51-45e7-a79a-1c159fbf6abc', 'PO 8.1', 'Intra-disciplinary Teamwork', 'Ability to work effectively as a team member or leader in intra-disciplinary teams (face-to-face, remote, or hybrid)', 12) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('0ea2ba03-0f19-45b0-a611-9d2c03824e1e', '3ae7e475-dd51-45e7-a79a-1c159fbf6abc', 'PO 8.2', 'Multidisciplinary Teamwork', 'Ability to work effectively as a team member or leader in multidisciplinary teams (face-to-face, remote, or hybrid)', 13) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('0c3a48bb-9459-43aa-a086-3932c130a298', '3ae7e475-dd51-45e7-a79a-1c159fbf6abc', 'PO 9.1', 'Oral Communication', 'Ability to communicate effectively orally on technical subjects, taking into account the diverse characteristics of the target audience (education, language, profession, etc.)', 14) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('0d7095b3-5cb8-4a5c-afde-449e63e2a50b', '3ae7e475-dd51-45e7-a79a-1c159fbf6abc', 'PO 9.2', 'Written Communication', 'Ability to communicate effectively in writing on technical subjects, taking into account the diverse characteristics of the target audience (education, language, profession, etc.)', 15) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('53171381-6d3f-4753-af88-c24c2fd9581f', '3ae7e475-dd51-45e7-a79a-1c159fbf6abc', 'PO 10.1', 'Business & Project Management', 'Knowledge of business practices such as project management and economic feasibility analysis', 16) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('1fe9b27f-d51d-43fd-a11a-e4e40916953b', '3ae7e475-dd51-45e7-a79a-1c159fbf6abc', 'PO 10.2', 'Entrepreneurship & Innovation', 'Awareness of entrepreneurship and innovation', 17) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('d621115f-0c16-41d0-a53d-512e4dd3ebc4', '3ae7e475-dd51-45e7-a79a-1c159fbf6abc', 'PO 11', 'Lifelong Learning', 'Ability to learn independently and continuously, adapt to new and emerging technologies, and think critically about technological changes', 18) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('fc1a0001-0000-4000-a000-000000000001', '3ae7e475-dd51-45e7-a79a-1c159fbf6abc', 'technical', 'Technical Content', 'Evaluates the depth, correctness, and originality of the engineering work itself — independent of how well it is communicated. Assesses whether the team applied appropriate engineering knowledge, justified their design decisions, and demonstrated real technical mastery.', 30, 30, '#F59E0B', '[{"min":27,"max":30,"label":"Excellent","description":"Problem is clearly defined with strong motivation. Design decisions are well-justified with engineering depth. Originality and mastery of relevant tools or methods are evident."},{"min":21,"max":26,"label":"Good","description":"Design is mostly clear and technically justified. Engineering decisions are largely supported."},{"min":13,"max":20,"label":"Developing","description":"Problem is stated but motivation or technical justification is insufficient."},{"min":0,"max":12,"label":"Insufficient","description":"Vague problem definition and unjustified decisions. Superficial technical content."}]', 1) ON CONFLICT (id) DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('fc1a0001-0000-4000-a000-000000000002', '3ae7e475-dd51-45e7-a79a-1c159fbf6abc', 'design', 'Written Communication', 'Evaluates how effectively the team communicates their project in written and visual form on the poster — including layout, information hierarchy, figure quality, and the clarity of technical content for a mixed audience.', 30, 30, '#22C55E', '[{"min":27,"max":30,"label":"Excellent","description":"Poster layout is intuitive with clear information flow. Visuals are fully labelled and high quality. Technical content is accessible to both technical and non-technical readers."},{"min":21,"max":26,"label":"Good","description":"Layout is mostly logical. Visuals are readable with minor gaps. Technical content is largely clear."},{"min":13,"max":20,"label":"Developing","description":"Occasional gaps in information flow. Some visuals are missing labels or captions. Technical content is only partially communicated."},{"min":0,"max":12,"label":"Insufficient","description":"Confusing layout. Low-quality or unlabelled visuals. Technical content is unclear or missing."}]', 2) ON CONFLICT (id) DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('fc1a0001-0000-4000-a000-000000000003', '3ae7e475-dd51-45e7-a79a-1c159fbf6abc', 'delivery', 'Oral Communication', 'Evaluates the team''s ability to present their work verbally and to respond to questions from jurors with varying technical backgrounds. A key factor is conscious audience adaptation.', 30, 30, '#3B82F6', '[{"min":27,"max":30,"label":"Excellent","description":"Presentation is consciously adapted for both technical and non-technical jury members. Q&A responses are accurate, clear, and audience-appropriate."},{"min":21,"max":26,"label":"Good","description":"Presentation is mostly clear and well-paced. Most questions answered correctly. Audience adaptation is generally evident."},{"min":13,"max":20,"label":"Developing","description":"Understandable but inconsistent. Limited audience adaptation. Time management or Q&A depth needs improvement."},{"min":0,"max":12,"label":"Insufficient","description":"Unclear or disorganised presentation. Most questions answered incorrectly or not at all."}]', 3) ON CONFLICT (id) DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('fc1a0001-0000-4000-a000-000000000004', '3ae7e475-dd51-45e7-a79a-1c159fbf6abc', 'teamwork', 'Teamwork', 'Evaluates visible evidence of equal and effective team participation during the poster session, as well as the group''s professional and ethical conduct in interacting with jurors.', 10, 10, '#EF4444', '[{"min":9,"max":10,"label":"Excellent","description":"All members participate actively and equally. Professional and ethical conduct observed throughout."},{"min":7,"max":8,"label":"Good","description":"Most members contribute. Minor knowledge gaps. Professionalism mostly observed."},{"min":4,"max":6,"label":"Developing","description":"Uneven participation. Some members are passive or unprepared."},{"min":0,"max":3,"label":"Insufficient","description":"Very low participation or dominated by one person. Lack of professionalism observed."}]', 4) ON CONFLICT (id) DO NOTHING;
