INSERT INTO frameworks (id, organization_id, name, description) VALUES ('253751a6-09dd-47d7-93b4-7064456e553c', NULL, 'ABET (2026 – 2027)', 'ABET EAC Student Outcomes — SO 1 through SO 7 (2026-2027 Criteria)') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('a527fe07-a97a-4483-ac3b-1cabf41d632a', '253751a6-09dd-47d7-93b4-7064456e553c', 'SO 1', 'Complex Problem Solving', 'Ability to identify, formulate, and solve complex engineering problems by applying principles of engineering, science, and mathematics.', 1) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('f0609d7e-15ce-43c8-a86a-1fd76bdc31bf', '253751a6-09dd-47d7-93b4-7064456e553c', 'SO 2', 'Engineering Design', 'Ability to apply engineering design to produce solutions that meet specified needs with consideration of public health, safety, and welfare, as well as global, cultural, social, environmental, and economic factors.', 2) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('9b6650ba-ea98-45dc-acde-44482bfba39d', '253751a6-09dd-47d7-93b4-7064456e553c', 'SO 3', 'Effective Communication', 'Ability to communicate effectively with a range of audiences.', 3) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('d91f4b07-37ef-416b-ad52-e7840c113648', '253751a6-09dd-47d7-93b4-7064456e553c', 'SO 4', 'Ethics & Professional Responsibility', 'Ability to recognize ethical and professional responsibilities in engineering situations and make informed judgments, which must consider the impact of engineering solutions in global, economic, environmental, and societal contexts.', 4) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('7827d7ab-fb8c-4118-a301-fd7e207c86ce', '253751a6-09dd-47d7-93b4-7064456e553c', 'SO 5', 'Teamwork & Leadership', 'Ability to function effectively on a team whose members together provide leadership, create a collaborative environment, establish goals, plan tasks, and meet objectives.', 5) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('a2469b25-73ee-48a2-aaa1-4c8fe094b2a0', '253751a6-09dd-47d7-93b4-7064456e553c', 'SO 6', 'Experimentation & Analysis', 'Ability to develop and conduct appropriate experimentation, analyze and interpret data, and use engineering judgment to draw conclusions.', 6) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('1a33e2d0-230a-48e8-ab51-9aa1ec9ccab6', '253751a6-09dd-47d7-93b4-7064456e553c', 'SO 7', 'Lifelong Learning', 'Ability to acquire and apply new knowledge as needed, using appropriate learning strategies.', 7) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO frameworks (id, organization_id, name, description) VALUES ('a1b2c3d4-e5f6-4000-a000-000000000001', NULL, 'VERA Standard', 'Generic capstone evaluation framework — 6 learning outcomes covering knowledge, design, communication, teamwork, and professional conduct') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('7d3f42cc-5c0b-4069-a668-8ea0cfadb363', 'a1b2c3d4-e5f6-4000-a000-000000000001', 'LO 1', 'Domain Knowledge', 'Ability to apply discipline-specific knowledge and methods to identify and solve complex real-world problems', 1) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('b8ed8649-3893-48f0-a6f8-fa102ee94df6', 'a1b2c3d4-e5f6-4000-a000-000000000001', 'LO 2', 'Design & Problem Solving', 'Ability to design and implement creative, feasible solutions that address well-defined requirements and constraints', 2) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('3431bc18-9075-421b-ad1f-650554c87955', 'a1b2c3d4-e5f6-4000-a000-000000000001', 'LO 3', 'Written Communication', 'Ability to communicate technical content clearly and effectively in written and visual form for audiences with varying levels of expertise', 3) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('f3d660b6-6a2c-4ea0-a19f-c03c4e450073', 'a1b2c3d4-e5f6-4000-a000-000000000001', 'LO 4', 'Oral Communication', 'Ability to present technical work verbally, adapt to the audience, and respond to expert questioning with accuracy and clarity', 4) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('9d802418-d562-471d-a240-9096a93f0d43', 'a1b2c3d4-e5f6-4000-a000-000000000001', 'LO 5', 'Teamwork & Collaboration', 'Ability to contribute effectively as a member or leader of a project team, demonstrating equal participation and shared responsibility', 5) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('3541d166-6c58-4033-a5e9-4d4c929c0126', 'a1b2c3d4-e5f6-4000-a000-000000000001', 'LO 6', 'Professional & Ethical Conduct', 'Awareness of professional responsibilities, ethical obligations, and the broader societal and environmental impact of technical work', 6) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('fc2a0001-0000-4000-a000-000000000001', 'a1b2c3d4-e5f6-4000-a000-000000000001', 'technical', 'Technical Content', 'Evaluates the depth, correctness, and originality of the project work — whether the team applied appropriate knowledge, justified their decisions, and demonstrated real mastery of the subject.', 30, 30, '#F59E0B', '[{"min":27,"max":30,"label":"Excellent","description":"Problem is clearly defined with strong motivation. Decisions are well-justified with technical depth. Originality and mastery of relevant methods are evident."},{"min":21,"max":26,"label":"Good","description":"Work is mostly clear and technically justified. Decisions are largely supported."},{"min":13,"max":20,"label":"Developing","description":"Problem is stated but motivation or technical justification is insufficient."},{"min":0,"max":12,"label":"Insufficient","description":"Vague problem definition and unjustified decisions. Superficial technical content."}]', 1) ON CONFLICT (id) DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('fc2a0001-0000-4000-a000-000000000002', 'a1b2c3d4-e5f6-4000-a000-000000000001', 'design', 'Written Communication', 'Evaluates how effectively the team communicates their project in written and visual form — including layout, information hierarchy, figure quality, and clarity for a mixed audience.', 30, 30, '#22C55E', '[{"min":27,"max":30,"label":"Excellent","description":"Layout is intuitive with clear information flow. Visuals are fully labelled and high quality. Content is accessible to both technical and non-technical readers."},{"min":21,"max":26,"label":"Good","description":"Layout is mostly logical. Visuals are readable with minor gaps. Content is largely clear."},{"min":13,"max":20,"label":"Developing","description":"Occasional gaps in information flow. Some visuals are missing labels. Content is only partially communicated."},{"min":0,"max":12,"label":"Insufficient","description":"Confusing layout. Low-quality or unlabelled visuals. Content is unclear or missing."}]', 2) ON CONFLICT (id) DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('fc2a0001-0000-4000-a000-000000000003', 'a1b2c3d4-e5f6-4000-a000-000000000001', 'delivery', 'Oral Communication', 'Evaluates the team''s ability to present their work verbally and respond to questions from evaluators with varying backgrounds. Audience adaptation is a key factor.', 30, 30, '#3B82F6', '[{"min":27,"max":30,"label":"Excellent","description":"Presentation is consciously adapted for both technical and non-technical evaluators. Q&A responses are accurate, clear, and audience-appropriate."},{"min":21,"max":26,"label":"Good","description":"Presentation is mostly clear and well-paced. Most questions answered correctly. Audience adaptation is generally evident."},{"min":13,"max":20,"label":"Developing","description":"Understandable but inconsistent. Limited audience adaptation. Time management or Q&A depth needs improvement."},{"min":0,"max":12,"label":"Insufficient","description":"Unclear or disorganised presentation. Most questions answered incorrectly or not at all."}]', 3) ON CONFLICT (id) DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('fc2a0001-0000-4000-a000-000000000004', 'a1b2c3d4-e5f6-4000-a000-000000000001', 'teamwork', 'Teamwork', 'Evaluates visible evidence of equal and effective team participation during the evaluation session, as well as the group''s professional and ethical conduct.', 10, 10, '#EF4444', '[{"min":9,"max":10,"label":"Excellent","description":"All members participate actively and equally. Professional and ethical conduct observed throughout."},{"min":7,"max":8,"label":"Good","description":"Most members contribute. Minor knowledge gaps. Professionalism mostly observed."},{"min":4,"max":6,"label":"Developing","description":"Uneven participation. Some members are passive or unprepared."},{"min":0,"max":3,"label":"Insufficient","description":"Very low participation or dominated by one person. Lack of professionalism observed."}]', 4) ON CONFLICT (id) DO NOTHING;
