INSERT INTO frameworks (id, organization_id, name, description) VALUES ('b877240d-f3f6-4934-a8da-978522f757a1', 'e802a6cb-6cfa-4a7c-aba6-2038490fb899', 'MÜDEK-S26-O', 'MÜDEK accreditation framework aligned with EUR-ACE standards. Evaluates engineering program outcomes across technical competency, design, communication, and teamwork dimensions.') ON CONFLICT DO NOTHING;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('21281bca-949e-47f5-ae60-dfc617e389e8', 'b877240d-f3f6-4934-a8da-978522f757a1', 'PO 1.1', 'Basic Knowledge', 'Knowledge in mathematics, natural sciences, basic engineering, computational methods, and discipline-specific topics', 1) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('9b40dba7-ecd8-4d5c-a9ef-5d2928d3c838', 'b877240d-f3f6-4934-a8da-978522f757a1', 'PO 1.2', 'Applied Knowledge', 'Ability to apply knowledge in mathematics, natural sciences, basic engineering, computational methods, and discipline-specific topics to solve complex engineering problems', 2) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('9765cbb9-4bc2-472b-adec-c0f56a728cc7', 'b877240d-f3f6-4934-a8da-978522f757a1', 'PO 2', 'Problem Analysis', 'Ability to identify, formulate, and analyze complex engineering problems using basic science, mathematics, and engineering knowledge while considering relevant UN Sustainable Development Goals', 3) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('28bc2bef-9913-43bf-a589-ea011c2f2dc3', 'b877240d-f3f6-4934-a8da-978522f757a1', 'PO 3.1', 'Creative Design', 'Ability to design creative solutions to complex engineering problems', 4) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('10b90aba-29ce-44c2-ab2a-7a57ad9235d0', 'b877240d-f3f6-4934-a8da-978522f757a1', 'PO 3.2', 'Complex Systems', 'Ability to design complex systems, processes, devices, or products that meet current and future requirements while considering realistic constraints and conditions', 5) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('6190a1f1-ca56-46d4-aafb-d587ae71e6d3', 'b877240d-f3f6-4934-a8da-978522f757a1', 'PO 4', 'Modern Tools', 'Ability to select and use appropriate techniques, resources, and modern engineering and IT tools, including estimation and modeling, for analysis and solution of complex engineering problems, with awareness of their limitations', 6) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('82cc6ad8-2c95-45d0-add9-1f14a25d215a', 'b877240d-f3f6-4934-a8da-978522f757a1', 'PO 5', 'Research Methods', 'Ability to use research methods including literature review, experiment design, data collection, result analysis, and interpretation for investigation of complex engineering problems', 7) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('c5700116-c207-4ae1-a79a-2b683b1e90eb', 'b877240d-f3f6-4934-a8da-978522f757a1', 'PO 6.1', 'Societal Impact', 'Knowledge of the impacts of engineering applications on society, health and safety, economy, sustainability, and environment within the scope of UN Sustainable Development Goals', 8) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('6674af46-b49e-4f25-a60b-7c487dfa82f7', 'b877240d-f3f6-4934-a8da-978522f757a1', 'PO 6.2', 'Legal Awareness', 'Awareness of the legal consequences of engineering solutions', 9) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('62ab931d-2b30-4f98-a613-e3946220bf6a', 'b877240d-f3f6-4934-a8da-978522f757a1', 'PO 7.1', 'Professional Ethics', 'Knowledge of acting in accordance with engineering professional principles and ethical responsibility', 10) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('781ce99c-d6a3-4813-aff5-7357a7c237ac', 'b877240d-f3f6-4934-a8da-978522f757a1', 'PO 7.2', 'Impartiality', 'Awareness of acting without discrimination and being inclusive of diversity', 11) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('cacd47f2-ccac-4899-a7d2-91e7edf74d3d', 'b877240d-f3f6-4934-a8da-978522f757a1', 'PO 8.1', 'Intra-disciplinary', 'Ability to work effectively as a team member or leader in intra-disciplinary teams (face-to-face, remote, or hybrid)', 12) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('b02ea8f2-8559-4fbd-a94c-dee70fb19842', 'b877240d-f3f6-4934-a8da-978522f757a1', 'PO 8.2', 'Multidisciplinary', 'Ability to work effectively as a team member or leader in multidisciplinary teams (face-to-face, remote, or hybrid)', 13) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('49a88448-b9a1-42e8-a5ec-1879859d9274', 'b877240d-f3f6-4934-a8da-978522f757a1', 'PO 9.1', 'Oral Communication', 'Ability to communicate effectively orally on technical subjects, taking into account the diverse characteristics of the target audience (education, language, profession, etc.)', 14) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('58514e5d-18c8-45e2-af99-2c97b6082b10', 'b877240d-f3f6-4934-a8da-978522f757a1', 'PO 9.2', 'Written Comms.', 'Ability to communicate effectively in writing on technical subjects, taking into account the diverse characteristics of the target audience (education, language, profession, etc.)', 15) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('dd2ea4b5-34f9-45f0-a2b9-ae7ab8606712', 'b877240d-f3f6-4934-a8da-978522f757a1', 'PO 10.1', 'Project Management', 'Knowledge of business practices such as project management and economic feasibility analysis', 16) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('67036ce8-2796-45cc-a8a9-43ba6299a6a5', 'b877240d-f3f6-4934-a8da-978522f757a1', 'PO 10.2', 'Entrepreneurship', 'Awareness of entrepreneurship and innovation', 17) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('8ee83fe1-1a5c-45e4-a08d-1cc021d389d3', 'b877240d-f3f6-4934-a8da-978522f757a1', 'PO 11', 'Lifelong Learning', 'Ability to learn independently and continuously, adapt to new and emerging technologies, and think critically about technological changes', 18) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO periods (id, organization_id, framework_id, name, season, description, start_date, end_date, is_locked, criteria_name, snapshot_frozen_at, activated_at, closed_at, updated_at) VALUES ('a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'e802a6cb-6cfa-4a7c-aba6-2038490fb899', 'b877240d-f3f6-4934-a8da-978522f757a1', 'Spring 2026', 'Spring', 'EE 491/492 Senior Design — 1-Day Poster Evaluation', CURRENT_DATE, CURRENT_DATE, false, 'MÜDEK-S26-R', (timestamp '2026-04-21 09:00:00' - interval '24 hours 0 minutes'), (timestamp '2026-04-21 09:00:00' - interval '62 hours 13 minutes'), NULL, (timestamp '2026-04-21 09:00:00' - interval '20 hours 0 minutes')) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('2ee71002-5476-4d79-a570-518ebf2a532f', 'b877240d-f3f6-4934-a8da-978522f757a1', 'technical', 'Technical Content', 'Evaluates the depth, correctness, and originality of the engineering work itself — independent of how well it is communicated. It assesses whether the team has applied appropriate engineering knowledge, justified their design decisions, and demonstrated real technical mastery.', 30, 30, '#F59E0B', '[{"min":27,"max":30,"label":"Excellent","description":"Problem is clearly defined with strong motivation. Design decisions are well-justified with engineering depth. Originality and mastery of relevant tools or methods are evident."},{"min":21,"max":26,"label":"Good","description":"Design is mostly clear and technically justified. Engineering decisions are largely supported."},{"min":13,"max":20,"label":"Developing","description":"Problem is stated but motivation or technical justification is insufficient."},{"min":0,"max":12,"label":"Insufficient","description":"Vague problem definition and unjustified decisions. Superficial technical content."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('787e905a-a2da-431e-af63-00cea2ea7bb5', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', '2ee71002-5476-4d79-a570-518ebf2a532f', 'technical', 'Technical Content', 'Evaluates the depth, correctness, and originality of the engineering work itself — independent of how well it is communicated. It assesses whether the team has applied appropriate engineering knowledge, justified their design decisions, and demonstrated real technical mastery.', 30, 30, '#F59E0B', '[{"min":27,"max":30,"label":"Excellent","description":"Problem is clearly defined with strong motivation. Design decisions are well-justified with engineering depth. Originality and mastery of relevant tools or methods are evident."},{"min":21,"max":26,"label":"Good","description":"Design is mostly clear and technically justified. Engineering decisions are largely supported."},{"min":13,"max":20,"label":"Developing","description":"Problem is stated but motivation or technical justification is insufficient."},{"min":0,"max":12,"label":"Insufficient","description":"Vague problem definition and unjustified decisions. Superficial technical content."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('ba345512-251e-4a8b-a903-df3d5a0e9882', 'b877240d-f3f6-4934-a8da-978522f757a1', 'design', 'Written Comms.', 'Evaluates how effectively the team communicates their project in written and visual form on the poster — including layout, information hierarchy, figure quality, and the clarity of technical content for a mixed audience (engineers and non-engineers alike).', 30, 30, '#22C55E', '[{"min":27,"max":30,"label":"Excellent","description":"Poster layout is intuitive with clear information flow. Visuals are fully labelled and high quality. Technical content is presented in a way accessible to both technical and non-technical readers."},{"min":21,"max":26,"label":"Good","description":"Layout is mostly logical. Visuals are readable with minor gaps. Technical content is largely clear with small areas for improvement."},{"min":13,"max":20,"label":"Developing","description":"Occasional gaps in information flow. Some visuals are missing labels or captions. Technical content is only partially communicated."},{"min":0,"max":12,"label":"Insufficient","description":"Confusing layout. Low-quality or unlabelled visuals. Technical content is unclear or missing."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('25fdf203-ff5f-4c31-ab09-3ac8bd726e65', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'ba345512-251e-4a8b-a903-df3d5a0e9882', 'design', 'Written Comms.', 'Evaluates how effectively the team communicates their project in written and visual form on the poster — including layout, information hierarchy, figure quality, and the clarity of technical content for a mixed audience (engineers and non-engineers alike).', 30, 30, '#22C55E', '[{"min":27,"max":30,"label":"Excellent","description":"Poster layout is intuitive with clear information flow. Visuals are fully labelled and high quality. Technical content is presented in a way accessible to both technical and non-technical readers."},{"min":21,"max":26,"label":"Good","description":"Layout is mostly logical. Visuals are readable with minor gaps. Technical content is largely clear with small areas for improvement."},{"min":13,"max":20,"label":"Developing","description":"Occasional gaps in information flow. Some visuals are missing labels or captions. Technical content is only partially communicated."},{"min":0,"max":12,"label":"Insufficient","description":"Confusing layout. Low-quality or unlabelled visuals. Technical content is unclear or missing."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('e3043f7b-006e-47aa-af42-8499f5ccb2d9', 'b877240d-f3f6-4934-a8da-978522f757a1', 'delivery', 'Oral Communication', 'Evaluates the team''s ability to present their work verbally and to respond to questions from jurors with varying technical backgrounds. A key factor is conscious audience adaptation — adjusting depth and vocabulary based on who is asking.', 30, 30, '#3B82F6', '[{"min":27,"max":30,"label":"Excellent","description":"Presentation is consciously adapted for both technical and non-technical jury members. Q&A responses are accurate, clear, and audience-appropriate."},{"min":21,"max":26,"label":"Good","description":"Presentation is mostly clear and well-paced. Most questions answered correctly. Audience adaptation is generally evident."},{"min":13,"max":20,"label":"Developing","description":"Understandable but inconsistent. Limited audience adaptation. Time management or Q&A depth needs improvement."},{"min":0,"max":12,"label":"Insufficient","description":"Unclear or disorganised presentation. Most questions answered incorrectly or not at all."}]', 3) ON CONFLICT DO NOTHING;
