INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('7c029bc5-197f-4df4-ad49-7c1d823cb23f', '9802ce58-a7ac-46ab-a798-88df97ec438a', 'PO 1.1', 'Basic Knowledge', 'Knowledge in mathematics, natural sciences, basic engineering, computational methods, and discipline-specific topics', 1) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('90f65048-a07f-40f8-a538-f450ba41db5b', '9802ce58-a7ac-46ab-a798-88df97ec438a', 'PO 1.2', 'Applied Knowledge', 'Ability to apply knowledge in mathematics, natural sciences, basic engineering, computational methods, and discipline-specific topics to solve complex engineering problems', 2) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('82a8ac0b-f0da-400c-acb0-592b3d5b3fc5', '9802ce58-a7ac-46ab-a798-88df97ec438a', 'PO 2', 'Problem Analysis', 'Ability to identify, formulate, and analyze complex engineering problems using basic science, mathematics, and engineering knowledge while considering relevant UN Sustainable Development Goals', 3) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('92c5add0-ae05-447b-a39f-75397c1b9e6a', '9802ce58-a7ac-46ab-a798-88df97ec438a', 'PO 3.1', 'Creative Design', 'Ability to design creative solutions to complex engineering problems', 4) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
