INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('d1a3acd3-a8ad-4d43-a712-30cbf6f6b3cc', '9802ce58-a7ac-46ab-a798-88df97ec438a', 'PO 6.1', 'Societal Impact', 'Knowledge of the impacts of engineering applications on society, health and safety, economy, sustainability, and environment within the scope of UN Sustainable Development Goals', 8) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
