INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('de31d5ab-91bf-4a0e-a95f-69009e34eb07', '338ccd66-e38d-4fa3-aa02-3869ec9ea46a', 'technical', 'Technical Content', 'Evaluates engineering problem formulation, design methodology, and application of domain-specific knowledge.', 30, 35, '#F59E0B', '[{"min":27,"max":30,"label":"Excellent","description":"Strong problem definition with well-justified design choices. Demonstrates deep domain knowledge."},{"min":21,"max":26,"label":"Good","description":"Problem is clearly stated. Design decisions are reasonable with minor justification gaps."},{"min":13,"max":20,"label":"Developing","description":"Problem statement exists but technical depth is shallow."},{"min":0,"max":12,"label":"Insufficient","description":"Vague problem definition. Design decisions are not supported."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('5c1f4f21-151a-4b22-a335-5ef961d9e99f', 'e55e0820-93f2-487f-abaa-4ae64a77e93e', 'de31d5ab-91bf-4a0e-a95f-69009e34eb07', 'technical', 'Technical Content', 'Evaluates engineering problem formulation, design methodology, and application of domain-specific knowledge.', 30, 35, '#F59E0B', '[{"min":27,"max":30,"label":"Excellent","description":"Strong problem definition with well-justified design choices. Demonstrates deep domain knowledge."},{"min":21,"max":26,"label":"Good","description":"Problem is clearly stated. Design decisions are reasonable with minor justification gaps."},{"min":13,"max":20,"label":"Developing","description":"Problem statement exists but technical depth is shallow."},{"min":0,"max":12,"label":"Insufficient","description":"Vague problem definition. Design decisions are not supported."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('64e3b16e-fe03-4538-a113-53c973546930', '338ccd66-e38d-4fa3-aa02-3869ec9ea46a', 'design', 'Written Report Quality', 'Assesses the quality and structure of the written report including references, formatting, and technical clarity.', 30, 25, '#22C55E', '[{"min":27,"max":30,"label":"Excellent","description":"Report is well-structured with clear sections, proper references, and professional formatting."},{"min":21,"max":26,"label":"Good","description":"Report covers required sections adequately. Formatting is mostly consistent."},{"min":13,"max":20,"label":"Developing","description":"Report structure is present but sections lack depth or proper citations."},{"min":0,"max":12,"label":"Insufficient","description":"Report is incomplete, poorly formatted, or missing critical sections."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('15dca296-abd2-4fd9-adb3-ff2d66b91858', 'e55e0820-93f2-487f-abaa-4ae64a77e93e', '64e3b16e-fe03-4538-a113-53c973546930', 'design', 'Written Report Quality', 'Assesses the quality and structure of the written report including references, formatting, and technical clarity.', 30, 25, '#22C55E', '[{"min":27,"max":30,"label":"Excellent","description":"Report is well-structured with clear sections, proper references, and professional formatting."},{"min":21,"max":26,"label":"Good","description":"Report covers required sections adequately. Formatting is mostly consistent."},{"min":13,"max":20,"label":"Developing","description":"Report structure is present but sections lack depth or proper citations."},{"min":0,"max":12,"label":"Insufficient","description":"Report is incomplete, poorly formatted, or missing critical sections."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('0b0465b4-513c-4756-a9f7-8b7a4380242b', '338ccd66-e38d-4fa3-aa02-3869ec9ea46a', 'delivery', 'Oral Presentation', 'Evaluates oral presentation skills including confidence, pacing, audience awareness, and Q&A handling.', 30, 25, '#3B82F6', '[{"min":27,"max":30,"label":"Excellent","description":"Clear, confident delivery with good pacing. Questions answered accurately and concisely."},{"min":21,"max":26,"label":"Good","description":"Presentation is understandable with adequate pacing. Most questions handled well."},{"min":13,"max":20,"label":"Developing","description":"Delivery is hesitant or rushed. Audience engagement is limited."},{"min":0,"max":12,"label":"Insufficient","description":"Disorganized presentation. Questions frequently answered incorrectly."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('01b94576-b441-4c66-ac35-be4aa17effa3', 'e55e0820-93f2-487f-abaa-4ae64a77e93e', '0b0465b4-513c-4756-a9f7-8b7a4380242b', 'delivery', 'Oral Presentation', 'Evaluates oral presentation skills including confidence, pacing, audience awareness, and Q&A handling.', 30, 25, '#3B82F6', '[{"min":27,"max":30,"label":"Excellent","description":"Clear, confident delivery with good pacing. Questions answered accurately and concisely."},{"min":21,"max":26,"label":"Good","description":"Presentation is understandable with adequate pacing. Most questions handled well."},{"min":13,"max":20,"label":"Developing","description":"Delivery is hesitant or rushed. Audience engagement is limited."},{"min":0,"max":12,"label":"Insufficient","description":"Disorganized presentation. Questions frequently answered incorrectly."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('7e6ffecc-9649-433c-a24b-195ed258b7c5', '338ccd66-e38d-4fa3-aa02-3869ec9ea46a', 'teamwork', 'Teamwork', 'Assesses balanced contribution across team members and individual understanding of the project scope.', 10, 15, '#EF4444', '[{"min":9,"max":10,"label":"Excellent","description":"All members participate actively and equally. Professional and ethical conduct observed throughout."},{"min":7,"max":8,"label":"Good","description":"Most members contribute. Minor knowledge gaps. Professionalism mostly observed."},{"min":4,"max":6,"label":"Developing","description":"Uneven participation. Some members are passive or unprepared."},{"min":0,"max":3,"label":"Insufficient","description":"Very low participation or dominated by one person. Lack of professionalism observed."}]', 4) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('7a7a05a9-ac9c-402d-aa04-6a07b69dccde', 'e55e0820-93f2-487f-abaa-4ae64a77e93e', '7e6ffecc-9649-433c-a24b-195ed258b7c5', 'teamwork', 'Teamwork', 'Assesses balanced contribution across team members and individual understanding of the project scope.', 10, 15, '#EF4444', '[{"min":9,"max":10,"label":"Excellent","description":"All members participate actively and equally. Professional and ethical conduct observed throughout."},{"min":7,"max":8,"label":"Good","description":"Most members contribute. Minor knowledge gaps. Professionalism mostly observed."},{"min":4,"max":6,"label":"Developing","description":"Uneven participation. Some members are passive or unprepared."},{"min":0,"max":3,"label":"Insufficient","description":"Very low participation or dominated by one person. Lack of professionalism observed."}]', 4) ON CONFLICT DO NOTHING;
