INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('6dba9ca5-78f5-4236-af01-c12257030072', 'e516c48e-17e4-40f1-af01-e756a2f95c6a', 'design', 'Written Report', 'Evaluates the organization, completeness, and clarity of the written project report.', 30, 25, '#22C55E', '[{"min":22,"max":30,"label":"Proficient","description":"Written report is organized and covers key design decisions."},{"min":14,"max":21,"label":"Developing","description":"Report exists but structure or content is incomplete."},{"min":0,"max":13,"label":"Below Standard","description":"Report is largely missing or disorganized."}]', 2) ON CONFLICT DO NOTHING;
