INSERT INTO frameworks (id, organization_id, name, description) VALUES ('bdd6007d-b924-4d61-a850-582668da427b', 'b94595d6-710c-4302-ad1b-11f4d216e028', 'ABET-S26-O', 'ABET Computing Accreditation Commission framework. Assesses student outcomes in computing knowledge, problem analysis, solution design, communication, and professional ethics.') ON CONFLICT DO NOTHING;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('21018dbd-a290-484b-a1d9-1f629cc706d3', 'bdd6007d-b924-4d61-a850-582668da427b', 'SO-1', 'Problem Solving', 'Ability to identify, formulate, and solve complex engineering problems by applying principles of engineering, science, and mathematics.', 1) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('0419ba14-9777-4c81-a5ed-539432ee78b3', 'bdd6007d-b924-4d61-a850-582668da427b', 'SO-2', 'Engineering Design', 'Ability to apply engineering design to produce solutions that meet specified needs with consideration of public health, safety, and welfare, as well as global, cultural, social, environmental, and economic factors.', 2) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('7ff5f637-7730-4df9-a6f9-3952c798ba57', 'bdd6007d-b924-4d61-a850-582668da427b', 'SO-3', 'Effective Comms.', 'Ability to communicate effectively with a range of audiences.', 3) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('c98e218e-5244-4210-a876-61eb5638e626', 'bdd6007d-b924-4d61-a850-582668da427b', 'SO-4', 'Ethics & Prof. Resp.', 'Ability to recognize ethical and professional responsibilities in engineering situations and make informed judgments, which must consider the impact of engineering solutions in global, economic, environmental, and societal contexts.', 4) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('2b41e243-476d-47ab-a58d-93267cf057eb', 'bdd6007d-b924-4d61-a850-582668da427b', 'SO-5', 'Teamwork & Lead.', 'Ability to function effectively on a team whose members together provide leadership, create a collaborative environment, establish goals, plan tasks, and meet objectives.', 5) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('0ebf13fe-f17a-4178-a030-7ad100ecfe9c', 'bdd6007d-b924-4d61-a850-582668da427b', 'SO-6', 'Experimentation', 'Ability to develop and conduct appropriate experimentation, analyze and interpret data, and use engineering judgment to draw conclusions.', 6) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('a26c46c9-1e70-42c3-afd1-d49db4835ade', 'bdd6007d-b924-4d61-a850-582668da427b', 'SO-7', 'Lifelong Learning', 'Ability to acquire and apply new knowledge as needed, using appropriate learning strategies.', 7) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
