INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('d1494a9d-dc24-4699-afa8-db0a15485425', 'bdd6007d-b924-4d61-a850-582668da427b', 'problem_solving', 'Problem Solving', 'Evaluates precision of problem formulation, scope definition, constraint identification, and correctness of the analytical approach.', 25, 25, '#EF4444', '[{"min":22,"max":25,"label":"Excellent","description":"Problem is precisely formulated with clear scope, constraints, and success metrics."},{"min":17,"max":21,"label":"Good","description":"Problem is well-defined. Minor gaps in constraint handling."},{"min":12,"max":16,"label":"Developing","description":"Problem statement exists but lacks precision."},{"min":0,"max":11,"label":"Insufficient","description":"Problem is vaguely defined with significant logical gaps."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('684fe08e-8aeb-4069-a864-a800f0e007aa', 'e14683dc-6ac1-4c73-a2cb-da24e9e4f45f', 'd1494a9d-dc24-4699-afa8-db0a15485425', 'problem_solving', 'Problem Solving', 'Evaluates precision of problem formulation, scope definition, constraint identification, and correctness of the analytical approach.', 25, 25, '#EF4444', '[{"min":22,"max":25,"label":"Excellent","description":"Problem is precisely formulated with clear scope, constraints, and success metrics."},{"min":17,"max":21,"label":"Good","description":"Problem is well-defined. Minor gaps in constraint handling."},{"min":12,"max":16,"label":"Developing","description":"Problem statement exists but lacks precision."},{"min":0,"max":11,"label":"Insufficient","description":"Problem is vaguely defined with significant logical gaps."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('8bcbc98d-6286-430e-aae3-89ccb81b1ca9', 'bdd6007d-b924-4d61-a850-582668da427b', 'system_design', 'System Design', 'Assesses architectural soundness, modularity, scalability, and justification of design decisions and component boundaries.', 25, 25, '#3B82F6', '[{"min":22,"max":25,"label":"Excellent","description":"Architecture is modular, scalable, and well-justified."},{"min":17,"max":21,"label":"Good","description":"Architecture is sound with clear component boundaries."},{"min":12,"max":16,"label":"Developing","description":"Basic architecture present but modularity concerns not addressed."},{"min":0,"max":11,"label":"Insufficient","description":"No clear architecture."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('6ddc3532-8a5c-41f0-a01c-80467a94d895', 'e14683dc-6ac1-4c73-a2cb-da24e9e4f45f', '8bcbc98d-6286-430e-aae3-89ccb81b1ca9', 'system_design', 'System Design', 'Assesses architectural soundness, modularity, scalability, and justification of design decisions and component boundaries.', 25, 25, '#3B82F6', '[{"min":22,"max":25,"label":"Excellent","description":"Architecture is modular, scalable, and well-justified."},{"min":17,"max":21,"label":"Good","description":"Architecture is sound with clear component boundaries."},{"min":12,"max":16,"label":"Developing","description":"Basic architecture present but modularity concerns not addressed."},{"min":0,"max":11,"label":"Insufficient","description":"No clear architecture."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('09de72b1-6571-49a4-ae79-6d48fc61a7a1', 'bdd6007d-b924-4d61-a850-582668da427b', 'implementation_quality', 'Implementation', 'Evaluates code quality, test coverage, documentation, and adherence to professional software engineering practices.', 20, 20, '#F59E0B', '[{"min":18,"max":20,"label":"Excellent","description":"Code is clean, well-tested, and follows best practices."},{"min":14,"max":17,"label":"Good","description":"Code is readable with adequate test coverage."},{"min":10,"max":13,"label":"Developing","description":"Code works but lacks tests or consistent style."},{"min":0,"max":9,"label":"Insufficient","description":"Code is disorganized, untested, or non-functional."}]', 3) ON CONFLICT DO NOTHING;
