INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('e7458d28-ba71-46e3-aa57-90a82b085e20', '9456dd6d-36ed-4f39-a421-f87f04005a65', 'SO-1', 'Problem Solving', 'Ability to identify, formulate, and solve complex engineering problems by applying principles of engineering, science, and mathematics.', 1) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('2a379731-bcff-4566-acf3-94b5e9c43905', '9456dd6d-36ed-4f39-a421-f87f04005a65', 'SO-2', 'Engineering Design', 'Ability to apply engineering design to produce solutions that meet specified needs with consideration of public health, safety, and welfare, as well as global, cultural, social, environmental, and economic factors.', 2) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('4c9f366a-8b94-4653-ab80-06c8a3f4f7e2', '9456dd6d-36ed-4f39-a421-f87f04005a65', 'SO-3', 'Effective Comms.', 'Ability to communicate effectively with a range of audiences.', 3) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('e66fecc1-18ba-4854-a086-53b085eee4f6', '9456dd6d-36ed-4f39-a421-f87f04005a65', 'SO-4', 'Ethics & Prof. Resp.', 'Ability to recognize ethical and professional responsibilities in engineering situations and make informed judgments, which must consider the impact of engineering solutions in global, economic, environmental, and societal contexts.', 4) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
