INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('705f752c-48c3-4b49-af9e-62a0ba13aaf2', '9456dd6d-36ed-4f39-a421-f87f04005a65', 'problem_solving', 'Problem Solving', 'Evaluates the precision of problem identification, scope definition, and correctness of the chosen analytical approach.', 25, 25, '#EF4444', '[{"min":22,"max":25,"label":"Excellent","description":"Problem is precisely formulated with clear scope, constraints, and success metrics."},{"min":17,"max":21,"label":"Good","description":"Problem is well-defined. Minor gaps in constraint handling."},{"min":12,"max":16,"label":"Developing","description":"Problem statement exists but lacks precision."},{"min":0,"max":11,"label":"Insufficient","description":"Problem is vaguely defined with significant logical gaps."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('b9f1f35c-7929-412b-a2c3-63e14ab7e9d0', 'b90e1112-88c7-44fa-a275-25bc0ad2d96d', '705f752c-48c3-4b49-af9e-62a0ba13aaf2', 'problem_solving', 'Problem Solving', 'Evaluates the precision of problem identification, scope definition, and correctness of the chosen analytical approach.', 25, 25, '#EF4444', '[{"min":22,"max":25,"label":"Excellent","description":"Problem is precisely formulated with clear scope, constraints, and success metrics."},{"min":17,"max":21,"label":"Good","description":"Problem is well-defined. Minor gaps in constraint handling."},{"min":12,"max":16,"label":"Developing","description":"Problem statement exists but lacks precision."},{"min":0,"max":11,"label":"Insufficient","description":"Problem is vaguely defined with significant logical gaps."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('2303ba74-0886-4ece-a97c-c35fe2915a29', '9456dd6d-36ed-4f39-a421-f87f04005a65', 'system_design', 'System Design', 'Assesses system architecture decisions, modularity, and the rationale behind component boundaries.', 25, 25, '#3B82F6', '[{"min":22,"max":25,"label":"Excellent","description":"Architecture is modular, scalable, and well-justified."},{"min":17,"max":21,"label":"Good","description":"Architecture is sound with clear component boundaries."},{"min":12,"max":16,"label":"Developing","description":"Basic architecture present but modularity concerns not addressed."},{"min":0,"max":11,"label":"Insufficient","description":"No clear architecture."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('d3dd5fe2-d521-4a2a-ae2b-bb11b6fa0902', 'b90e1112-88c7-44fa-a275-25bc0ad2d96d', '2303ba74-0886-4ece-a97c-c35fe2915a29', 'system_design', 'System Design', 'Assesses system architecture decisions, modularity, and the rationale behind component boundaries.', 25, 25, '#3B82F6', '[{"min":22,"max":25,"label":"Excellent","description":"Architecture is modular, scalable, and well-justified."},{"min":17,"max":21,"label":"Good","description":"Architecture is sound with clear component boundaries."},{"min":12,"max":16,"label":"Developing","description":"Basic architecture present but modularity concerns not addressed."},{"min":0,"max":11,"label":"Insufficient","description":"No clear architecture."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('f2d5aaa3-eb65-44a8-ad99-ccaf62111a38', '9456dd6d-36ed-4f39-a421-f87f04005a65', 'implementation_quality', 'Implementation', 'Evaluates code organization, test coverage, and adherence to software engineering best practices.', 20, 18, '#F59E0B', '[{"min":18,"max":20,"label":"Excellent","description":"Code is clean, well-tested, and follows best practices."},{"min":14,"max":17,"label":"Good","description":"Code is readable with adequate test coverage."},{"min":10,"max":13,"label":"Developing","description":"Code works but lacks tests or consistent style."},{"min":0,"max":9,"label":"Insufficient","description":"Code is disorganized, untested, or non-functional."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('2a39ada5-da79-4403-aec0-8299b6747419', 'b90e1112-88c7-44fa-a275-25bc0ad2d96d', 'f2d5aaa3-eb65-44a8-ad99-ccaf62111a38', 'implementation_quality', 'Implementation', 'Evaluates code organization, test coverage, and adherence to software engineering best practices.', 20, 18, '#F59E0B', '[{"min":18,"max":20,"label":"Excellent","description":"Code is clean, well-tested, and follows best practices."},{"min":14,"max":17,"label":"Good","description":"Code is readable with adequate test coverage."},{"min":10,"max":13,"label":"Developing","description":"Code works but lacks tests or consistent style."},{"min":0,"max":9,"label":"Insufficient","description":"Code is disorganized, untested, or non-functional."}]', 3) ON CONFLICT DO NOTHING;
