INSERT INTO frameworks (id, organization_id, name, description) VALUES ('6a75953b-1d93-4211-a422-1ec468526b45', 'b94595d6-710c-4302-ad1b-11f4d216e028', 'ABET-S25-O', 'ABET Computing Accreditation Commission framework. Assesses student outcomes in computing knowledge, problem analysis, solution design, communication, and professional ethics.') ON CONFLICT DO NOTHING;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('c17db0de-2b5e-41fc-a067-5b47a37fab17', '6a75953b-1d93-4211-a422-1ec468526b45', 'SO-1', 'Problem Solving', 'Ability to identify, formulate, and solve complex engineering problems by applying principles of engineering, science, and mathematics.', 1) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('1c08f16a-40a9-427c-ac0d-fa193efd1ce7', '6a75953b-1d93-4211-a422-1ec468526b45', 'SO-2', 'Engineering Design', 'Ability to apply engineering design to produce solutions that meet specified needs with consideration of public health, safety, and welfare, as well as global, cultural, social, environmental, and economic factors.', 2) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('80f6f634-a9dd-42a7-a10d-8a8185582300', '6a75953b-1d93-4211-a422-1ec468526b45', 'SO-3', 'Effective Comms.', 'Ability to communicate effectively with a range of audiences.', 3) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('ce62eb25-fda2-411e-abf8-7bfc8460f54b', '6a75953b-1d93-4211-a422-1ec468526b45', 'SO-4', 'Ethics & Prof. Resp.', 'Ability to recognize ethical and professional responsibilities in engineering situations and make informed judgments, which must consider the impact of engineering solutions in global, economic, environmental, and societal contexts.', 4) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('f290d24a-6f71-4a55-a43e-a3251aa41199', '6a75953b-1d93-4211-a422-1ec468526b45', 'SO-5', 'Teamwork & Lead.', 'Ability to function effectively on a team whose members together provide leadership, create a collaborative environment, establish goals, plan tasks, and meet objectives.', 5) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('77129525-faa3-4f97-a00d-6e13de5cceaa', '6a75953b-1d93-4211-a422-1ec468526b45', 'SO-6', 'Experimentation', 'Ability to develop and conduct appropriate experimentation, analyze and interpret data, and use engineering judgment to draw conclusions.', 6) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
