INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('31b6e047-2925-4e26-a1f1-d0667bc84195', '6a75953b-1d93-4211-a422-1ec468526b45', 'problem_solving', 'Analytical Thinking', 'Assesses analytical rigor, problem decomposition quality, and identification of constraints and edge cases.', 25, 30, '#EF4444', '[{"min":22,"max":25,"label":"Excellent","description":"Demonstrates rigorous analytical thinking with precise problem decomposition."},{"min":17,"max":21,"label":"Good","description":"Analysis is mostly thorough with clear problem breakdown."},{"min":12,"max":16,"label":"Developing","description":"Some analytical effort but decomposition is incomplete."},{"min":0,"max":11,"label":"Insufficient","description":"Lacks systematic analytical approach."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('53700e90-0bef-4410-aa0f-3995053ad8a2', '0e963024-a53f-4722-a9e0-5db7a47b4419', '31b6e047-2925-4e26-a1f1-d0667bc84195', 'problem_solving', 'Analytical Thinking', 'Assesses analytical rigor, problem decomposition quality, and identification of constraints and edge cases.', 25, 30, '#EF4444', '[{"min":22,"max":25,"label":"Excellent","description":"Demonstrates rigorous analytical thinking with precise problem decomposition."},{"min":17,"max":21,"label":"Good","description":"Analysis is mostly thorough with clear problem breakdown."},{"min":12,"max":16,"label":"Developing","description":"Some analytical effort but decomposition is incomplete."},{"min":0,"max":11,"label":"Insufficient","description":"Lacks systematic analytical approach."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('49223b7e-9bff-4e09-aa2c-be52ac29f5a0', '6a75953b-1d93-4211-a422-1ec468526b45', 'system_design', 'Software Architecture', 'Evaluates architectural soundness, component modularity, interface design, and scalability considerations.', 25, 25, '#3B82F6', '[{"min":22,"max":25,"label":"Excellent","description":"Architecture is clean, modular, and well-documented with clear rationale."},{"min":17,"max":21,"label":"Good","description":"Architecture is reasonable with identifiable component boundaries."},{"min":12,"max":16,"label":"Developing","description":"Some structure exists but architectural choices are ad-hoc."},{"min":0,"max":11,"label":"Insufficient","description":"No discernible architecture or design rationale."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('7e8b2e8b-4a9a-4d2c-a87b-955d58d51b03', '0e963024-a53f-4722-a9e0-5db7a47b4419', '49223b7e-9bff-4e09-aa2c-be52ac29f5a0', 'system_design', 'Software Architecture', 'Evaluates architectural soundness, component modularity, interface design, and scalability considerations.', 25, 25, '#3B82F6', '[{"min":22,"max":25,"label":"Excellent","description":"Architecture is clean, modular, and well-documented with clear rationale."},{"min":17,"max":21,"label":"Good","description":"Architecture is reasonable with identifiable component boundaries."},{"min":12,"max":16,"label":"Developing","description":"Some structure exists but architectural choices are ad-hoc."},{"min":0,"max":11,"label":"Insufficient","description":"No discernible architecture or design rationale."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('002515a1-f66f-42e9-ac36-832552da8132', '6a75953b-1d93-4211-a422-1ec468526b45', 'implementation_quality', 'Implementation', 'Assesses code quality, testing strategy, continuous integration practices, and documentation completeness.', 20, 20, '#F59E0B', '[{"min":18,"max":20,"label":"Excellent","description":"Code is clean, well-tested, and follows best practices."},{"min":14,"max":17,"label":"Good","description":"Code is readable with adequate test coverage."},{"min":10,"max":13,"label":"Developing","description":"Code works but lacks tests or consistent style."},{"min":0,"max":9,"label":"Insufficient","description":"Code is disorganized, untested, or non-functional."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('5bab7e88-65ad-43a7-a14f-8b9bbcb9c9af', '0e963024-a53f-4722-a9e0-5db7a47b4419', '002515a1-f66f-42e9-ac36-832552da8132', 'implementation_quality', 'Implementation', 'Assesses code quality, testing strategy, continuous integration practices, and documentation completeness.', 20, 20, '#F59E0B', '[{"min":18,"max":20,"label":"Excellent","description":"Code is clean, well-tested, and follows best practices."},{"min":14,"max":17,"label":"Good","description":"Code is readable with adequate test coverage."},{"min":10,"max":13,"label":"Developing","description":"Code works but lacks tests or consistent style."},{"min":0,"max":9,"label":"Insufficient","description":"Code is disorganized, untested, or non-functional."}]', 3) ON CONFLICT DO NOTHING;
