INSERT INTO frameworks (id, organization_id, name, description) VALUES ('a1d5264d-2409-40dc-a726-0fa4b957342e', 'b94595d6-710c-4302-ad1b-11f4d216e028', 'ABET-F24-O', 'ABET Computing Accreditation Commission framework. Assesses student outcomes in computing knowledge, problem analysis, solution design, communication, and professional ethics.') ON CONFLICT DO NOTHING;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('f485329f-3e3c-48bb-a813-b4cca3874ce6', 'a1d5264d-2409-40dc-a726-0fa4b957342e', 'SO-1', 'Problem Solving', 'Ability to identify, formulate, and solve complex engineering problems by applying principles of engineering, science, and mathematics.', 1) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('280cf9b3-1f20-4f35-a8f8-9d19fe281ff5', 'a1d5264d-2409-40dc-a726-0fa4b957342e', 'SO-2', 'Engineering Design', 'Ability to apply engineering design to produce solutions that meet specified needs with consideration of public health, safety, and welfare, as well as global, cultural, social, environmental, and economic factors.', 2) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('d7dd2501-44f0-4fba-af81-db33c51e6fd2', 'a1d5264d-2409-40dc-a726-0fa4b957342e', 'SO-3', 'Effective Comms.', 'Ability to communicate effectively with a range of audiences.', 3) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('374573bb-7195-4dfc-a605-80e42f50294b', 'a1d5264d-2409-40dc-a726-0fa4b957342e', 'SO-4', 'Ethics & Prof. Resp.', 'Ability to recognize ethical and professional responsibilities in engineering situations and make informed judgments, which must consider the impact of engineering solutions in global, economic, environmental, and societal contexts.', 4) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('47048708-6415-4b45-a9b7-adc67b7d6b27', 'a1d5264d-2409-40dc-a726-0fa4b957342e', 'SO-5', 'Teamwork & Lead.', 'Ability to function effectively on a team whose members together provide leadership, create a collaborative environment, establish goals, plan tasks, and meet objectives.', 5) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('af4280c4-de96-40f3-a70c-e74da47491fd', 'a1d5264d-2409-40dc-a726-0fa4b957342e', 'SO-6', 'Experimentation', 'Ability to develop and conduct appropriate experimentation, analyze and interpret data, and use engineering judgment to draw conclusions.', 6) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('7a1f4efc-a6c6-4c67-a1a7-9a6b77386da6', 'a1d5264d-2409-40dc-a726-0fa4b957342e', 'SO-7', 'Lifelong Learning', 'Ability to acquire and apply new knowledge as needed, using appropriate learning strategies.', 7) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO periods (id, organization_id, framework_id, name, season, description, start_date, end_date, is_locked, criteria_name, snapshot_frozen_at, activated_at, closed_at, updated_at) VALUES ('f8c01197-da4a-4646-a42d-8dc74715e3bc', 'b94595d6-710c-4302-ad1b-11f4d216e028', 'a1d5264d-2409-40dc-a726-0fa4b957342e', 'Fall 2024', 'Fall', 'CS Fall Capstone — 1-Day Demo Day', '2024-12-07', '2024-12-07', false, 'ABET-F24-R', (timestamp '2024-12-07 09:00:00' - interval '24 hours 0 minutes'), (timestamp '2024-12-07 09:00:00' + interval '53 hours 13 minutes'), (timestamp '2024-12-07 09:00:00' + interval '24 hours 0 minutes'), (timestamp '2024-12-07 09:00:00' + interval '96 hours 0 minutes')) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('700c6664-3ed5-4c36-a9f8-2da46bd23031', 'a1d5264d-2409-40dc-a726-0fa4b957342e', 'problem_solving', 'Analytical Thinking', 'Evaluates structured problem decomposition, constraint analysis, and the rigor of the proposed solution approach.', 25, 30, '#EF4444', '[{"min":22,"max":25,"label":"Excellent","description":"Exceptional analytical rigor. Problem is fully decomposed with constraints identified."},{"min":17,"max":21,"label":"Good","description":"Solid analytical approach covering most problem dimensions."},{"min":12,"max":16,"label":"Developing","description":"Analysis is surface-level. Key constraints overlooked."},{"min":0,"max":11,"label":"Insufficient","description":"Problem is treated superficially with no structured thinking."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('9ec0420a-7f95-4e3f-ad37-b95948485c65', 'f8c01197-da4a-4646-a42d-8dc74715e3bc', '700c6664-3ed5-4c36-a9f8-2da46bd23031', 'problem_solving', 'Analytical Thinking', 'Evaluates structured problem decomposition, constraint analysis, and the rigor of the proposed solution approach.', 25, 30, '#EF4444', '[{"min":22,"max":25,"label":"Excellent","description":"Exceptional analytical rigor. Problem is fully decomposed with constraints identified."},{"min":17,"max":21,"label":"Good","description":"Solid analytical approach covering most problem dimensions."},{"min":12,"max":16,"label":"Developing","description":"Analysis is surface-level. Key constraints overlooked."},{"min":0,"max":11,"label":"Insufficient","description":"Problem is treated superficially with no structured thinking."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('da87a1b8-43db-41a8-ab07-5b00793459c5', 'a1d5264d-2409-40dc-a726-0fa4b957342e', 'system_design', 'Software Architecture', 'Assesses software architecture quality including component cohesion, interface clarity, and design rationale.', 25, 30, '#3B82F6', '[{"min":22,"max":25,"label":"Excellent","description":"Textbook-quality architecture. Components are cohesive with well-defined interfaces."},{"min":17,"max":21,"label":"Good","description":"Architecture is functional with reasonable separation of concerns."},{"min":12,"max":16,"label":"Developing","description":"Monolithic or poorly factored. Dependencies are tangled."},{"min":0,"max":11,"label":"Insufficient","description":"No coherent architecture. Code organization is arbitrary."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('52f96a98-1ac8-4b6e-aa3c-02ab77905c16', 'f8c01197-da4a-4646-a42d-8dc74715e3bc', 'da87a1b8-43db-41a8-ab07-5b00793459c5', 'system_design', 'Software Architecture', 'Assesses software architecture quality including component cohesion, interface clarity, and design rationale.', 25, 30, '#3B82F6', '[{"min":22,"max":25,"label":"Excellent","description":"Textbook-quality architecture. Components are cohesive with well-defined interfaces."},{"min":17,"max":21,"label":"Good","description":"Architecture is functional with reasonable separation of concerns."},{"min":12,"max":16,"label":"Developing","description":"Monolithic or poorly factored. Dependencies are tangled."},{"min":0,"max":11,"label":"Insufficient","description":"No coherent architecture. Code organization is arbitrary."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('890b46de-0f9f-44c5-a804-a891fc883836', 'a1d5264d-2409-40dc-a726-0fa4b957342e', 'implementation_quality', 'Implementation', 'Evaluates overall code health, test adequacy, build reproducibility, and deployment readiness.', 20, 20, '#F59E0B', '[{"min":18,"max":20,"label":"Excellent","description":"Code is clean, well-tested, and follows best practices."},{"min":14,"max":17,"label":"Good","description":"Code is readable with adequate test coverage."},{"min":10,"max":13,"label":"Developing","description":"Code works but lacks tests or consistent style."},{"min":0,"max":9,"label":"Insufficient","description":"Code is disorganized, untested, or non-functional."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('e242e868-2bb7-4869-af4b-7ad480080c56', 'f8c01197-da4a-4646-a42d-8dc74715e3bc', '890b46de-0f9f-44c5-a804-a891fc883836', 'implementation_quality', 'Implementation', 'Evaluates overall code health, test adequacy, build reproducibility, and deployment readiness.', 20, 20, '#F59E0B', '[{"min":18,"max":20,"label":"Excellent","description":"Code is clean, well-tested, and follows best practices."},{"min":14,"max":17,"label":"Good","description":"Code is readable with adequate test coverage."},{"min":10,"max":13,"label":"Developing","description":"Code works but lacks tests or consistent style."},{"min":0,"max":9,"label":"Insufficient","description":"Code is disorganized, untested, or non-functional."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('71e93a50-031e-47f5-aba7-32e85edeefe8', 'a1d5264d-2409-40dc-a726-0fa4b957342e', 'communication', 'Communication & Collaboration', 'Assesses project documentation quality, team collaboration evidence, and the ability to present technical work clearly.', 20, 20, '#EC4899', '[{"min":18,"max":20,"label":"Excellent","description":"Documentation is comprehensive. Team collaboration workflow is clearly demonstrated."},{"min":14,"max":17,"label":"Good","description":"Documentation covers key areas. Evidence of collaborative process."},{"min":10,"max":13,"label":"Developing","description":"Documentation is sparse. Collaboration is mentioned but not demonstrated."},{"min":0,"max":9,"label":"Insufficient","description":"Little documentation. No evidence of structured collaboration."}]', 4) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('e6928c81-092d-4b96-ada3-5dcf9bab3962', 'f8c01197-da4a-4646-a42d-8dc74715e3bc', '71e93a50-031e-47f5-aba7-32e85edeefe8', 'communication', 'Communication & Collaboration', 'Assesses project documentation quality, team collaboration evidence, and the ability to present technical work clearly.', 20, 20, '#EC4899', '[{"min":18,"max":20,"label":"Excellent","description":"Documentation is comprehensive. Team collaboration workflow is clearly demonstrated."},{"min":14,"max":17,"label":"Good","description":"Documentation covers key areas. Evidence of collaborative process."},{"min":10,"max":13,"label":"Developing","description":"Documentation is sparse. Collaboration is mentioned but not demonstrated."},{"min":0,"max":9,"label":"Insufficient","description":"Little documentation. No evidence of structured collaboration."}]', 4) ON CONFLICT DO NOTHING;
