INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('09f5a628-6f6a-4f0b-aad4-968de4cbf1c3', 'c8c99fe9-0961-4048-a6f0-8d78bcf50237', 'TC-1', 'Autonomy & Control', 'Aircraft performs autonomous take-off, flight, landing, and target lock-on; manual mode switching results in point deductions per competition rules.', 1) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
