INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('8e2515ff-125b-40ea-af7b-5489d5e8ce83', 'c8c99fe9-0961-4048-a6f0-8d78bcf50237', 'TC-3', 'Tech Report Quality', 'Preliminary Design Report (PDR) and Critical Design Report (CDR) assessed for completeness, technical rigor, Turkish grammar compliance, and documentation standards.', 3) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
