INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('b85e9071-96f9-497e-abb1-e12911afb941', 'c8c99fe9-0961-4048-a6f0-8d78bcf50237', 'preliminary_report', 'Design Report (ODR)', 'Evaluates completeness of the preliminary design report, mission definition clarity, and feasibility of the proposed design.', 25, 25, '#6366F1', '[{"min":22,"max":25,"label":"Excellent","description":"Report is comprehensive with clear mission definition and feasible preliminary design."},{"min":17,"max":21,"label":"Good","description":"Report covers key design elements with adequate justification."},{"min":12,"max":16,"label":"Developing","description":"Report structure is present but design rationale is weak."},{"min":0,"max":11,"label":"Insufficient","description":"Report is incomplete or missing critical sections."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('3827321e-25d3-4ec5-ab6a-d8fb8d5f65fd', 'e77bf882-fc32-461c-acab-6ee1696df0c7', 'b85e9071-96f9-497e-abb1-e12911afb941', 'preliminary_report', 'Design Report (ODR)', 'Evaluates completeness of the preliminary design report, mission definition clarity, and feasibility of the proposed design.', 25, 25, '#6366F1', '[{"min":22,"max":25,"label":"Excellent","description":"Report is comprehensive with clear mission definition and feasible preliminary design."},{"min":17,"max":21,"label":"Good","description":"Report covers key design elements with adequate justification."},{"min":12,"max":16,"label":"Developing","description":"Report structure is present but design rationale is weak."},{"min":0,"max":11,"label":"Insufficient","description":"Report is incomplete or missing critical sections."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('70e52056-be0d-483f-ab90-4c7bb2e2f68c', 'c8c99fe9-0961-4048-a6f0-8d78bcf50237', 'critical_design', 'Design Review (KTR)', 'Assesses design maturity, subsystem integration completeness, and manufacturing readiness at the CDR milestone.', 30, 30, '#F59E0B', '[{"min":27,"max":30,"label":"Excellent","description":"Design is mature, manufacturable, and all subsystems well-integrated."},{"min":21,"max":26,"label":"Good","description":"Design is mostly complete with minor integration gaps."},{"min":13,"max":20,"label":"Developing","description":"Design shows progress but subsystem integration unclear."},{"min":0,"max":12,"label":"Insufficient","description":"Design is immature or not viable for manufacturing."}]', 2) ON CONFLICT DO NOTHING;
