INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('1fa94557-05f7-4ba6-ac6f-2078c9cce06f', 'c7583f54-fc5a-4d04-a334-60cce3dda8d0', 'preliminary_report', 'Design Report (ODR)', 'Assesses preliminary design report completeness, mission clarity, and feasibility of the proposed concept.', 25, 20, '#6366F1', '[{"min":22,"max":25,"label":"Excellent","description":"Report is thorough with well-reasoned mission definition and a feasible preliminary design."},{"min":17,"max":21,"label":"Good","description":"Report covers key design elements with adequate technical justification."},{"min":12,"max":16,"label":"Developing","description":"Report structure is present but design rationale is underdeveloped."},{"min":0,"max":11,"label":"Insufficient","description":"Report is incomplete or missing critical sections."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('9fc5d438-f3ea-4966-ad57-e9ba3626497e', '308d2708-dbea-41b6-a1c8-da6129445759', '1fa94557-05f7-4ba6-ac6f-2078c9cce06f', 'preliminary_report', 'Design Report (ODR)', 'Assesses preliminary design report completeness, mission clarity, and feasibility of the proposed concept.', 25, 20, '#6366F1', '[{"min":22,"max":25,"label":"Excellent","description":"Report is thorough with well-reasoned mission definition and a feasible preliminary design."},{"min":17,"max":21,"label":"Good","description":"Report covers key design elements with adequate technical justification."},{"min":12,"max":16,"label":"Developing","description":"Report structure is present but design rationale is underdeveloped."},{"min":0,"max":11,"label":"Insufficient","description":"Report is incomplete or missing critical sections."}]', 1) ON CONFLICT DO NOTHING;
