INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('156b6ad7-c428-4675-a2e8-a369aa93fa2a', '30e3f1b6-3e49-42e7-a58f-c74c3032de29', 'preliminary_report', 'Design Report (ODR)', 'Assesses the thoroughness and technical depth of the preliminary design documentation.', 25, 30, '#6366F1', '[{"min":22,"max":25,"label":"Excellent","description":"Report is comprehensive with clear mission definition and feasible preliminary design."},{"min":17,"max":21,"label":"Good","description":"Report covers key design elements with adequate justification."},{"min":12,"max":16,"label":"Developing","description":"Report structure is present but design rationale is weak."},{"min":0,"max":11,"label":"Insufficient","description":"Report is incomplete or missing critical sections."}]', 1) ON CONFLICT DO NOTHING;
