INSERT INTO frameworks (id, organization_id, name, description) VALUES ('ea8c174a-5b3e-4f32-a0b4-1a4cb4a866bd', '088f5054-c9df-4c7f-a679-c1321524f250', 'RCF-2026-O', 'TÜBİTAK 2204-A ulusal lise öğrencileri araştırma projeleri yarışması değerlendirme çerçevesi. Bilimsel yöntem, araştırma derinliği, özgünlük ve sözlü savunma kalitesi ölçütlerine göre puanlanır.') ON CONFLICT DO NOTHING;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('e876b29d-6608-4a2c-a9df-db8089c8ec72', 'ea8c174a-5b3e-4f32-a0b4-1a4cb4a866bd', 'RC-1', 'Orig. & Creativity', 'Research question addresses a genuine, unstudied gap in scientific literature; approach is independent of textbook procedures and demonstrates student-initiated inquiry rather than replication.', 1) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('db1c1805-d1ba-4973-a045-888c6c52dcc9', 'ea8c174a-5b3e-4f32-a0b4-1a4cb4a866bd', 'RC-2', 'Scientific Method', 'Hypothesis is precisely formulated and testable; experimental design includes appropriate control and variable isolation; sample size is statistically sufficient; results are reproducible and reported with uncertainty bounds.', 2) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('692a9874-d1d9-4118-ac06-f6116543d650', 'ea8c174a-5b3e-4f32-a0b4-1a4cb4a866bd', 'RC-3', 'Literature Review', 'Background research is comprehensive, citations are current and from peer-reviewed sources, and prior work is critically synthesised to motivate the research question rather than summarised superficially.', 3) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('d6fc4ce3-c377-4f61-af3f-1c0f5ccc7391', 'ea8c174a-5b3e-4f32-a0b4-1a4cb4a866bd', 'RC-4', 'App. & Impact', 'Findings address a real-world problem with a credible pathway to practical implementation; potential societal, environmental, or economic benefit is quantified or clearly argued.', 4) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('a10a4f99-1f3a-464b-ab38-d67180b1ccef', 'ea8c174a-5b3e-4f32-a0b4-1a4cb4a866bd', 'RC-5', 'Ethics & Safety', 'All applicable research ethics protocols are observed (informed consent, animal welfare, chemical/biological hazard procedures); ethical approval documentation is present where required by TÜBİTAK guidelines.', 5) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('b62ba66c-11ac-425a-a0de-f082e174ef8a', 'ea8c174a-5b3e-4f32-a0b4-1a4cb4a866bd', 'RC-6', 'Comp. & Synthesis', 'Presenter demonstrates mastery of underlying scientific principles, accurately interprets own data, and provides satisfactory, technically sound answers to jury questions without coaching.', 6) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
