INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('cdf4a217-3fe1-42af-ac31-ed20d6bcd071', '0557fbec-1fd6-42b9-a594-54fe33568352', 'scientific_method', 'Scientific Method', 'Assesses experimental design rigor, hypothesis clarity, and statistical validity of results.', 40, 35, '#3B82F6', '[{"min":35,"max":40,"label":"Excellent","description":"Hypothesis is precisely formulated, controls are appropriate, and results are reproducible."},{"min":27,"max":34,"label":"Good","description":"Methodology is sound with minor gaps in controls or sample adequacy."},{"min":19,"max":26,"label":"Developing","description":"Basic methodology is described but controls or statistical validity are weak."},{"min":0,"max":18,"label":"Insufficient","description":"No discernible experimental design or hypothesis testing."}]', 2) ON CONFLICT DO NOTHING;
