INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('90ac3ef1-e022-4371-af8b-0800cf4b486a', 'd032f441-9f8b-4539-aed4-afde1f41d068', 'impact_and_presentation', 'Impact Assessment', 'Assesses data-driven impact analysis and the quality of oral and visual presentation delivery.', 25, 25, '#F59E0B', '[{"min":22,"max":25,"label":"Excellent","description":"Impact assessment is data-driven with clear societal or scientific benefit."},{"min":17,"max":21,"label":"Good","description":"Impact is identified and reasonably supported with evidence."},{"min":12,"max":16,"label":"Developing","description":"Impact is mentioned but assessment is vague or unsupported."},{"min":0,"max":11,"label":"Insufficient","description":"No structured impact assessment provided."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('795dd7aa-24c7-44df-acd2-44dbb529189c', '3f9cabdb-61dc-45da-afa5-dbb1747cd8c8', '90ac3ef1-e022-4371-af8b-0800cf4b486a', 'impact_and_presentation', 'Impact Assessment', 'Assesses data-driven impact analysis and the quality of oral and visual presentation delivery.', 25, 25, '#F59E0B', '[{"min":22,"max":25,"label":"Excellent","description":"Impact assessment is data-driven with clear societal or scientific benefit."},{"min":17,"max":21,"label":"Good","description":"Impact is identified and reasonably supported with evidence."},{"min":12,"max":16,"label":"Developing","description":"Impact is mentioned but assessment is vague or unsupported."},{"min":0,"max":11,"label":"Insufficient","description":"No structured impact assessment provided."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO period_outcomes (id, period_id, source_outcome_id, code, label, description, sort_order) VALUES ('3df65d7d-879e-4bff-a891-87fbffe29653', '3f9cabdb-61dc-45da-afa5-dbb1747cd8c8', '73458d45-1903-408c-a62b-817f3abc7897', 'RC-1', 'Orig. & Creativity', 'Research question addresses a genuine, unstudied gap in scientific literature; approach is independent of textbook procedures and demonstrates student-initiated inquiry rather than replication.', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_outcomes (id, period_id, source_outcome_id, code, label, description, sort_order) VALUES ('0f33a1de-6900-4758-ae0f-816b2b43a3f3', '3f9cabdb-61dc-45da-afa5-dbb1747cd8c8', '8dc4eb80-2e33-478d-a217-470d2ecd067b', 'RC-2', 'Scientific Method', 'Hypothesis is precisely formulated and testable; experimental design includes appropriate control and variable isolation; sample size is statistically sufficient; results are reproducible and reported with uncertainty bounds.', 2) ON CONFLICT DO NOTHING;
INSERT INTO period_outcomes (id, period_id, source_outcome_id, code, label, description, sort_order) VALUES ('e1beba2b-0e40-41e3-a632-91a9155cfd21', '3f9cabdb-61dc-45da-afa5-dbb1747cd8c8', 'e6bd5dcc-0da8-44f2-a95e-9822ba9f2e40', 'RC-3', 'Literature Review', 'Background research is comprehensive, citations are current and from peer-reviewed sources, and prior work is critically synthesised to motivate the research question rather than summarised superficially.', 3) ON CONFLICT DO NOTHING;
INSERT INTO period_outcomes (id, period_id, source_outcome_id, code, label, description, sort_order) VALUES ('387cfa40-f275-427b-a459-4f12dbec2138', '3f9cabdb-61dc-45da-afa5-dbb1747cd8c8', '9d1b7035-b028-4bab-a261-b719052c11a0', 'RC-4', 'App. & Impact', 'Findings address a real-world problem with a credible pathway to practical implementation; potential societal, environmental, or economic benefit is quantified or clearly argued.', 4) ON CONFLICT DO NOTHING;
INSERT INTO period_outcomes (id, period_id, source_outcome_id, code, label, description, sort_order) VALUES ('3a3dea08-a9ef-45d4-a6c6-13d1e3fc852d', '3f9cabdb-61dc-45da-afa5-dbb1747cd8c8', '3ac64f22-d2d8-4b19-aee8-d7e1fd8dcc4c', 'RC-5', 'Ethics & Safety', 'All applicable research ethics protocols are observed (informed consent, animal welfare, chemical/biological hazard procedures); ethical approval documentation is present where required by TÜBİTAK guidelines.', 5) ON CONFLICT DO NOTHING;
INSERT INTO period_outcomes (id, period_id, source_outcome_id, code, label, description, sort_order) VALUES ('8b101a5b-cc7b-496e-a8d6-838a115ab171', '3f9cabdb-61dc-45da-afa5-dbb1747cd8c8', '47226863-def9-4574-a5c8-e15206399702', 'RC-6', 'Comp. & Synthesis', 'Presenter demonstrates mastery of underlying scientific principles, accurately interprets own data, and provides satisfactory, technically sound answers to jury questions without coaching.', 6) ON CONFLICT DO NOTHING;
INSERT INTO period_outcomes (id, period_id, source_outcome_id, code, label, description, sort_order) VALUES ('f9300092-87c9-4463-ad6b-222bfde95eb2', '3f9cabdb-61dc-45da-afa5-dbb1747cd8c8', 'adb8164e-7539-45ee-a956-b290d2af2f19', 'RC-7', 'Scope Clarity', 'Research boundaries are clearly delineated; objectives are specific, measurable, and achievable within the declared timeframe; limitations are acknowledged and their effect on conclusions is discussed.', 7) ON CONFLICT DO NOTHING;
