INSERT INTO frameworks (id, organization_id, name, description) VALUES ('f306a580-0806-48f7-a6e5-4d40f96dbfdf', 'ff81ecf1-13ac-44b2-a331-0a207a8c7184', 'DCF-2026-O', 'IEEE AP-S Student Design Contest framework. Evaluates antenna design performance, technical documentation quality, oral presentation, and adherence to contest specifications.') ON CONFLICT DO NOTHING;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('860cd687-dfab-4353-abb1-4a027da3d251', 'f306a580-0806-48f7-a6e5-4d40f96dbfdf', 'DC-1', 'Creativity & Innov.', 'Design introduces a novel antenna topology, feeding mechanism, or material application not commonly documented in current literature; innovation is substantiated by comparative analysis against state-of-the-art solutions.', 1) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('bce7ee6b-2be7-4a4c-a232-adc5730f3cc9', 'f306a580-0806-48f7-a6e5-4d40f96dbfdf', 'DC-2', 'Technical Merit', 'Simulated and measured antenna parameters (gain, bandwidth, radiation pattern, impedance matching) are in close agreement; RF performance meets or exceeds the specified design requirements for the target application.', 2) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('a3d2281a-d24f-44ac-af6d-351b36d866d3', 'f306a580-0806-48f7-a6e5-4d40f96dbfdf', 'DC-3', 'Fab. & Validation', 'Prototype is cleanly fabricated with dimensional accuracy; measured S-parameters and radiation characteristics are obtained via calibrated vector network analyser and anechoic chamber or comparable measurement setup.', 3) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('bd859cd7-9a6d-4f62-afb8-b263a6a34449', 'f306a580-0806-48f7-a6e5-4d40f96dbfdf', 'DC-4', 'Practical App.', 'A specific real-world use case (e.g., 5G mmWave, vehicular radar, biomedical implant, IoT sensor) is clearly defined; design trade-offs are directly linked to application constraints such as size, frequency band, or power level.', 4) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('6e3997b7-a8f1-42a5-a360-e2736eaddd74', 'f306a580-0806-48f7-a6e5-4d40f96dbfdf', 'DC-5', 'Oral Pres. & Q&A', 'Team presents the complete design process — requirements, synthesis, simulation, fabrication, and measurement — in a structured and fluent manner; technical questions from the judging panel are answered accurately and confidently.', 5) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
