INSERT INTO frameworks (id, organization_id, name, description) VALUES ('2a7f179a-5433-492f-a7eb-c2a163251cf0', 'ff81ecf1-13ac-44b2-a331-0a207a8c7184', 'DCF-2025-O', 'IEEE AP-S Student Design Contest framework. Evaluates antenna design performance, technical documentation quality, oral presentation, and adherence to contest specifications.') ON CONFLICT DO NOTHING;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('a13b6e78-da23-4f45-a663-884f30c4d85d', '2a7f179a-5433-492f-a7eb-c2a163251cf0', 'DC-1', 'Creativity & Innov.', 'Design introduces a novel antenna topology, feeding mechanism, or material application not commonly documented in current literature; innovation is substantiated by comparative analysis against state-of-the-art solutions.', 1) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('cd5293bb-0809-4478-a75c-2bb5667fe045', '2a7f179a-5433-492f-a7eb-c2a163251cf0', 'DC-2', 'Technical Merit', 'Simulated and measured antenna parameters (gain, bandwidth, radiation pattern, impedance matching) are in close agreement; RF performance meets or exceeds the specified design requirements for the target application.', 2) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('1b94dda7-95a8-4d7c-aa46-de6dc03f83a2', '2a7f179a-5433-492f-a7eb-c2a163251cf0', 'DC-3', 'Fab. & Validation', 'Prototype is cleanly fabricated with dimensional accuracy; measured S-parameters and radiation characteristics are obtained via calibrated vector network analyser and anechoic chamber or comparable measurement setup.', 3) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('436f85ce-f5f6-43c1-a96f-e2907ecd2f55', '2a7f179a-5433-492f-a7eb-c2a163251cf0', 'DC-4', 'Practical App.', 'A specific real-world use case (e.g., 5G mmWave, vehicular radar, biomedical implant, IoT sensor) is clearly defined; design trade-offs are directly linked to application constraints such as size, frequency band, or power level.', 4) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('9ca031d6-4b21-4e02-a7ec-4848297b3653', '2a7f179a-5433-492f-a7eb-c2a163251cf0', 'DC-5', 'Oral Pres. & Q&A', 'Team presents the complete design process — requirements, synthesis, simulation, fabrication, and measurement — in a structured and fluent manner; technical questions from the judging panel are answered accurately and confidently.', 5) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO periods (id, organization_id, framework_id, name, season, description, start_date, end_date, is_locked, criteria_name, snapshot_frozen_at, activated_at, closed_at, updated_at) VALUES ('318124ea-8614-4355-ad48-2486524dfc13', 'ff81ecf1-13ac-44b2-a331-0a207a8c7184', '2a7f179a-5433-492f-a7eb-c2a163251cf0', '2025 Contest', 'Evaluation', 'IEEE AP-S Student Design Contest 2025 — 2-Day Evaluation (Jul 25–26)', '2025-07-25', '2025-07-26', false, 'DCF-2025-R', (timestamp '2025-07-25 09:00:00' - interval '24 hours 0 minutes'), (timestamp '2025-07-25 09:00:00' + interval '31 hours 55 minutes'), (timestamp '2025-07-26 09:00:00' + interval '24 hours 0 minutes'), (timestamp '2025-07-25 09:00:00' + interval '120 hours 0 minutes')) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('aa310223-9172-4c0f-a696-a42b1d72b3e8', '2a7f179a-5433-492f-a7eb-c2a163251cf0', 'creativity', 'Creativity', 'Evaluates novelty of the antenna design concept relative to existing literature and published designs.', 30, 35, '#EC4899', '[{"min":27,"max":30,"label":"Excellent","description":"Design introduces a genuinely novel topology or technique with clear differentiation from published work."},{"min":21,"max":26,"label":"Good","description":"Design shows meaningful originality in at least one dimension of the antenna concept."},{"min":13,"max":20,"label":"Developing","description":"Conventional approach with incremental modifications. Limited differentiation from prior art."},{"min":0,"max":12,"label":"Insufficient","description":"Direct application of standard designs with no discernible creative contribution."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('f9fff257-dd3c-402c-a751-be4cd5b12e92', '318124ea-8614-4355-ad48-2486524dfc13', 'aa310223-9172-4c0f-a696-a42b1d72b3e8', 'creativity', 'Creativity', 'Evaluates novelty of the antenna design concept relative to existing literature and published designs.', 30, 35, '#EC4899', '[{"min":27,"max":30,"label":"Excellent","description":"Design introduces a genuinely novel topology or technique with clear differentiation from published work."},{"min":21,"max":26,"label":"Good","description":"Design shows meaningful originality in at least one dimension of the antenna concept."},{"min":13,"max":20,"label":"Developing","description":"Conventional approach with incremental modifications. Limited differentiation from prior art."},{"min":0,"max":12,"label":"Insufficient","description":"Direct application of standard designs with no discernible creative contribution."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('f5943a0a-15b2-4897-a619-f4ee918cd222', '2a7f179a-5433-492f-a7eb-c2a163251cf0', 'technical_merit', 'Technical Merit', 'Assesses simulation-measurement agreement quality and overall antenna performance metrics.', 40, 40, '#3B82F6', '[{"min":35,"max":40,"label":"Excellent","description":"Simulation and measurement results are in close agreement. RF performance exceeds specifications."},{"min":27,"max":34,"label":"Good","description":"Results are solid with acceptable sim-measurement correlation and adequate performance."},{"min":19,"max":26,"label":"Developing","description":"Simulation results presented but measurement validation is limited or inconsistent."},{"min":0,"max":18,"label":"Insufficient","description":"Significant discrepancies between simulation and measurement or no measured results."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('e64b33e7-ae8d-4c65-a011-618a8d31e2c4', '318124ea-8614-4355-ad48-2486524dfc13', 'f5943a0a-15b2-4897-a619-f4ee918cd222', 'technical_merit', 'Technical Merit', 'Assesses simulation-measurement agreement quality and overall antenna performance metrics.', 40, 40, '#3B82F6', '[{"min":35,"max":40,"label":"Excellent","description":"Simulation and measurement results are in close agreement. RF performance exceeds specifications."},{"min":27,"max":34,"label":"Good","description":"Results are solid with acceptable sim-measurement correlation and adequate performance."},{"min":19,"max":26,"label":"Developing","description":"Simulation results presented but measurement validation is limited or inconsistent."},{"min":0,"max":18,"label":"Insufficient","description":"Significant discrepancies between simulation and measurement or no measured results."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('cff6ccde-f406-4a11-a48b-a805b2690c85', '2a7f179a-5433-492f-a7eb-c2a163251cf0', 'application_and_presentation', 'Application & Demo', 'Evaluates the clarity of the proposed real-world use case and the quality of the live demonstration.', 30, 25, '#F59E0B', '[{"min":27,"max":30,"label":"Excellent","description":"Live demo is compelling and clearly demonstrates a real-world application scenario."},{"min":21,"max":26,"label":"Good","description":"Demo works and application context is well-established."},{"min":13,"max":20,"label":"Developing","description":"Demo is partial or application scenario is not convincing."},{"min":0,"max":12,"label":"Insufficient","description":"No working demo or application context."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('364bedf6-a50f-425c-aa45-3567c85d5ff8', '318124ea-8614-4355-ad48-2486524dfc13', 'cff6ccde-f406-4a11-a48b-a805b2690c85', 'application_and_presentation', 'Application & Demo', 'Evaluates the clarity of the proposed real-world use case and the quality of the live demonstration.', 30, 25, '#F59E0B', '[{"min":27,"max":30,"label":"Excellent","description":"Live demo is compelling and clearly demonstrates a real-world application scenario."},{"min":21,"max":26,"label":"Good","description":"Demo works and application context is well-established."},{"min":13,"max":20,"label":"Developing","description":"Demo is partial or application scenario is not convincing."},{"min":0,"max":12,"label":"Insufficient","description":"No working demo or application context."}]', 3) ON CONFLICT DO NOTHING;
