INSERT INTO frameworks (id, organization_id, name, description) VALUES ('6b6d9035-b8e1-4c0d-a353-173b485a32b7', 'ff81ecf1-13ac-44b2-a331-0a207a8c7184', 'DCF-2024-O', 'IEEE AP-S Student Design Contest framework. Evaluates antenna design performance, technical documentation quality, oral presentation, and adherence to contest specifications.') ON CONFLICT DO NOTHING;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('8ce256d0-618c-4c23-ae38-caade50731a6', '6b6d9035-b8e1-4c0d-a353-173b485a32b7', 'DC-1', 'Creativity & Innov.', 'Design introduces a novel antenna topology, feeding mechanism, or material application not commonly documented in current literature; innovation is substantiated by comparative analysis against state-of-the-art solutions.', 1) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('42577109-f5ba-4cef-ab70-887342a1eab5', '6b6d9035-b8e1-4c0d-a353-173b485a32b7', 'DC-2', 'Technical Merit', 'Simulated and measured antenna parameters (gain, bandwidth, radiation pattern, impedance matching) are in close agreement; RF performance meets or exceeds the specified design requirements for the target application.', 2) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('4311d17e-fe35-43f3-a2a7-e1e7db1cc4f9', '6b6d9035-b8e1-4c0d-a353-173b485a32b7', 'DC-3', 'Fab. & Validation', 'Prototype is cleanly fabricated with dimensional accuracy; measured S-parameters and radiation characteristics are obtained via calibrated vector network analyser and anechoic chamber or comparable measurement setup.', 3) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('ba6280d8-7605-41a9-a3e1-8f830fd647f7', '6b6d9035-b8e1-4c0d-a353-173b485a32b7', 'DC-4', 'Practical App.', 'A specific real-world use case (e.g., 5G mmWave, vehicular radar, biomedical implant, IoT sensor) is clearly defined; design trade-offs are directly linked to application constraints such as size, frequency band, or power level.', 4) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('d0b710b6-03d9-4b66-ad76-537a08ca2731', '6b6d9035-b8e1-4c0d-a353-173b485a32b7', 'DC-5', 'Oral Pres. & Q&A', 'Team presents the complete design process — requirements, synthesis, simulation, fabrication, and measurement — in a structured and fluent manner; technical questions from the judging panel are answered accurately and confidently.', 5) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
