INSERT INTO frameworks (id, organization_id, name, description) VALUES ('31533723-2866-4854-a0fb-a3230477529f', '2060c696-71f7-4a57-a7c9-d3bcdc9db763', 'MF-2026-O', 'CanSat Competition mission evaluation framework. Assesses satellite container design, mission objective completion, telemetry data quality, and post-flight analysis report.') ON CONFLICT DO NOTHING;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('c80c83ee-7f9d-420d-ab7a-fcb4e9b909b3', '31533723-2866-4854-a0fb-a3230477529f', 'CS-1', 'Design Compliance', 'CanSat fits within the prescribed cylindrical envelope (66 mm × 115 mm, ≤ 310 g); all structural, thermal, and power budgets are documented with positive margins and verified against flight hardware.', 1) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('f68aa0e5-befe-40df-ad78-c1e5ea75baaf', '31533723-2866-4854-a0fb-a3230477529f', 'CS-2', 'Primary Mission', 'Air pressure and air temperature are sampled at ≥ 1 Hz throughout descent; data is stored on-board and simultaneously downlinked to the ground station; post-flight data completeness exceeds 95 % of expected samples.', 2) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('12386d06-971a-4e0f-a04c-d9678c8a7679', '31533723-2866-4854-a0fb-a3230477529f', 'CS-3', 'Secondary Mission', 'Team-defined secondary mission demonstrates scientific or engineering creativity (e.g., imaging, atmospheric sensing, attitude determination); mission objective is novel, clearly scoped, and successfully executed in flight.', 3) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('954c528e-8b70-4042-a037-ba21aa9fecc0', '31533723-2866-4854-a0fb-a3230477529f', 'CS-4', 'Descent & Recovery', 'Passive descent system achieves a terminal velocity between 10 m/s and 15 m/s throughout the altitude range; CanSat is recovered intact with no damage to electronics or structure after landing.', 4) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('9c814665-ca79-43da-ab8c-b70b21191d44', '31533723-2866-4854-a0fb-a3230477529f', 'CS-5', 'Ground Station', 'Ground station software displays real-time telemetry in engineering units with visual altitude and temperature plots; data is automatically logged to CSV; any reception gaps are flagged and interpolated correctly.', 5) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('ee375b13-ae65-46e9-a4a0-2127b109b131', '31533723-2866-4854-a0fb-a3230477529f', 'CS-6', 'Analysis & Docs', 'Post-flight report includes altitude profile reconstruction, temperature-altitude correlation, sensor calibration discussion, anomaly root-cause analysis, and quantitative comparison between predicted and measured performance.', 6) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('d2a3cf4b-b4aa-468a-a9a6-1307e3b8ed34', '31533723-2866-4854-a0fb-a3230477529f', 'CS-7', 'Range Safety', 'All range safety rules are followed including pre-flight hardware inspection, parachute deployment verification, launch pad clearance procedures, and post-flight range sweep; no safety violations are recorded by range safety officers.', 7) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO periods (id, organization_id, framework_id, name, season, description, start_date, end_date, is_locked, criteria_name, snapshot_frozen_at, activated_at, closed_at, updated_at) VALUES ('b0cb348c-59b5-407f-a21e-e6d514d0dd4b', '2060c696-71f7-4a57-a7c9-d3bcdc9db763', '31533723-2866-4854-a0fb-a3230477529f', '2026 Season', 'Spring', 'CanSat 2026 Launch Competition — 1-Day Finals (Demo)', CURRENT_DATE, CURRENT_DATE, false, 'MF-2026-R', (timestamp '2026-04-21 09:00:00' - interval '24 hours 0 minutes'), (timestamp '2026-04-21 09:00:00' - interval '67 hours 40 minutes'), NULL, (timestamp '2026-04-21 09:00:00' - interval '20 hours 0 minutes')) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('1b23585c-42ba-4eb3-a89b-930f7685b423', '31533723-2866-4854-a0fb-a3230477529f', 'design_compliance', 'Design Compliance', 'Evaluates adherence to all specified volume, mass, and structural design constraints, with documented margin analysis.', 20, 20, '#6366F1', '[{"min":18,"max":20,"label":"Excellent","description":"All constraints fully met with documented margin analysis."},{"min":14,"max":17,"label":"Good","description":"Constraints met with minor deviations."},{"min":10,"max":13,"label":"Developing","description":"One or more constraints marginally exceeded."},{"min":0,"max":9,"label":"Insufficient","description":"Multiple constraints violated."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('39ad5067-8dda-4e64-ae73-d184d756fcb8', 'b0cb348c-59b5-407f-a21e-e6d514d0dd4b', '1b23585c-42ba-4eb3-a89b-930f7685b423', 'design_compliance', 'Design Compliance', 'Evaluates adherence to all specified volume, mass, and structural design constraints, with documented margin analysis.', 20, 20, '#6366F1', '[{"min":18,"max":20,"label":"Excellent","description":"All constraints fully met with documented margin analysis."},{"min":14,"max":17,"label":"Good","description":"Constraints met with minor deviations."},{"min":10,"max":13,"label":"Developing","description":"One or more constraints marginally exceeded."},{"min":0,"max":9,"label":"Insufficient","description":"Multiple constraints violated."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('27be752e-ac42-457d-ad7b-a26103812c0f', '31533723-2866-4854-a0fb-a3230477529f', 'mission_execution', 'Mission & Telemetry', 'Assesses successful execution of primary and secondary mission objectives with continuous and reliable telemetry throughout the flight.', 35, 35, '#EF4444', '[{"min":31,"max":35,"label":"Excellent","description":"Primary and secondary missions fully executed. Continuous telemetry."},{"min":24,"max":30,"label":"Good","description":"Primary mission completed. Minor telemetry gaps."},{"min":17,"max":23,"label":"Developing","description":"Primary mission partially completed."},{"min":0,"max":16,"label":"Insufficient","description":"Mission fails to execute."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('a4130608-7ef6-4aa0-a200-e282cf5a2741', 'b0cb348c-59b5-407f-a21e-e6d514d0dd4b', '27be752e-ac42-457d-ad7b-a26103812c0f', 'mission_execution', 'Mission & Telemetry', 'Assesses successful execution of primary and secondary mission objectives with continuous and reliable telemetry throughout the flight.', 35, 35, '#EF4444', '[{"min":31,"max":35,"label":"Excellent","description":"Primary and secondary missions fully executed. Continuous telemetry."},{"min":24,"max":30,"label":"Good","description":"Primary mission completed. Minor telemetry gaps."},{"min":17,"max":23,"label":"Developing","description":"Primary mission partially completed."},{"min":0,"max":16,"label":"Insufficient","description":"Mission fails to execute."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('e1690a0c-5c04-46b6-a0c3-4ea420397f4e', '31533723-2866-4854-a0fb-a3230477529f', 'data_and_documentation', 'Data Analysis', 'Evaluates depth and appropriateness of post-flight data analysis and the overall quality and completeness of written documentation.', 25, 25, '#3B82F6', '[{"min":22,"max":25,"label":"Excellent","description":"Flight data thoroughly analyzed with appropriate methods."},{"min":17,"max":21,"label":"Good","description":"Data analysis competent. Post-flight report addresses key findings."},{"min":12,"max":16,"label":"Developing","description":"Data presented but analysis shallow."},{"min":0,"max":11,"label":"Insufficient","description":"Raw data dump with no meaningful analysis."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('47971fb8-8cd5-4387-a33f-d2bca79d9c62', 'b0cb348c-59b5-407f-a21e-e6d514d0dd4b', 'e1690a0c-5c04-46b6-a0c3-4ea420397f4e', 'data_and_documentation', 'Data Analysis', 'Evaluates depth and appropriateness of post-flight data analysis and the overall quality and completeness of written documentation.', 25, 25, '#3B82F6', '[{"min":22,"max":25,"label":"Excellent","description":"Flight data thoroughly analyzed with appropriate methods."},{"min":17,"max":21,"label":"Good","description":"Data analysis competent. Post-flight report addresses key findings."},{"min":12,"max":16,"label":"Developing","description":"Data presented but analysis shallow."},{"min":0,"max":11,"label":"Insufficient","description":"Raw data dump with no meaningful analysis."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('5392f417-62aa-4588-a04a-1823c3051974', '31533723-2866-4854-a0fb-a3230477529f', 'safety_and_recovery', 'Safety & Recovery', 'Assesses adherence to all range safety procedures, descent rate control within specification, and successful CanSat recovery.', 20, 20, '#10B981', '[{"min":18,"max":20,"label":"Excellent","description":"Recovered intact. Descent rate within spec. All safety procedures followed."},{"min":14,"max":17,"label":"Good","description":"Recovery successful with minor issues."},{"min":10,"max":13,"label":"Developing","description":"Recovery partial or descent rate deviates."},{"min":0,"max":9,"label":"Insufficient","description":"CanSat lost or damaged."}]', 4) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('1e464d58-b7b3-4e4a-a9c3-25d8f06304ab', 'b0cb348c-59b5-407f-a21e-e6d514d0dd4b', '5392f417-62aa-4588-a04a-1823c3051974', 'safety_and_recovery', 'Safety & Recovery', 'Assesses adherence to all range safety procedures, descent rate control within specification, and successful CanSat recovery.', 20, 20, '#10B981', '[{"min":18,"max":20,"label":"Excellent","description":"Recovered intact. Descent rate within spec. All safety procedures followed."},{"min":14,"max":17,"label":"Good","description":"Recovery successful with minor issues."},{"min":10,"max":13,"label":"Developing","description":"Recovery partial or descent rate deviates."},{"min":0,"max":9,"label":"Insufficient","description":"CanSat lost or damaged."}]', 4) ON CONFLICT DO NOTHING;
INSERT INTO period_outcomes (id, period_id, source_outcome_id, code, label, description, sort_order) VALUES ('a67c2809-86e8-4f89-a725-efb361a776f3', 'b0cb348c-59b5-407f-a21e-e6d514d0dd4b', 'c80c83ee-7f9d-420d-ab7a-fcb4e9b909b3', 'CS-1', 'Design Compliance', 'CanSat fits within the prescribed cylindrical envelope (66 mm × 115 mm, ≤ 310 g); all structural, thermal, and power budgets are documented with positive margins and verified against flight hardware.', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_outcomes (id, period_id, source_outcome_id, code, label, description, sort_order) VALUES ('88ebc16d-daf5-4e9b-ab4e-85e1f3e4afae', 'b0cb348c-59b5-407f-a21e-e6d514d0dd4b', 'f68aa0e5-befe-40df-ad78-c1e5ea75baaf', 'CS-2', 'Primary Mission', 'Air pressure and air temperature are sampled at ≥ 1 Hz throughout descent; data is stored on-board and simultaneously downlinked to the ground station; post-flight data completeness exceeds 95 % of expected samples.', 2) ON CONFLICT DO NOTHING;
INSERT INTO period_outcomes (id, period_id, source_outcome_id, code, label, description, sort_order) VALUES ('852f748e-eb01-46d3-aa79-39ac506ee618', 'b0cb348c-59b5-407f-a21e-e6d514d0dd4b', '12386d06-971a-4e0f-a04c-d9678c8a7679', 'CS-3', 'Secondary Mission', 'Team-defined secondary mission demonstrates scientific or engineering creativity (e.g., imaging, atmospheric sensing, attitude determination); mission objective is novel, clearly scoped, and successfully executed in flight.', 3) ON CONFLICT DO NOTHING;
INSERT INTO period_outcomes (id, period_id, source_outcome_id, code, label, description, sort_order) VALUES ('6c26293c-26b9-4bbe-a5fe-fed5c4de04b8', 'b0cb348c-59b5-407f-a21e-e6d514d0dd4b', '954c528e-8b70-4042-a037-ba21aa9fecc0', 'CS-4', 'Descent & Recovery', 'Passive descent system achieves a terminal velocity between 10 m/s and 15 m/s throughout the altitude range; CanSat is recovered intact with no damage to electronics or structure after landing.', 4) ON CONFLICT DO NOTHING;
