INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('87be3034-29a4-417e-a5e4-df40eeb1fac3', 'c8021bb8-fd12-4826-a314-7139a5971fe5', 'af83992d-afce-4c5c-a8d8-40ecfc5c0d17', 'mission_execution', 'Mission & Telemetry', 'Evaluates primary and secondary mission objective completion with continuous telemetry reliability.', 35, 40, '#EF4444', '[{"min":31,"max":35,"label":"Excellent","description":"Both primary and secondary missions fully executed. Telemetry is continuous and complete throughout flight."},{"min":24,"max":30,"label":"Good","description":"Primary mission completed. Secondary mission attempted with minor gaps in telemetry."},{"min":17,"max":23,"label":"Developing","description":"Primary mission partially completed. Significant telemetry gaps or secondary mission not attempted."},{"min":0,"max":16,"label":"Insufficient","description":"Mission execution failed or no meaningful flight data collected."}]', 2) ON CONFLICT DO NOTHING;
