INSERT INTO period_outcomes (id, period_id, source_outcome_id, code, label, description, sort_order) VALUES ('9db63df6-2ef1-483d-a7df-47f0ebb6f8a7', 'c8021bb8-fd12-4826-a314-7139a5971fe5', '47b075c9-f024-4624-a78a-ab9e7720164c', 'CS-1', 'Design Compliance', 'CanSat fits within the prescribed cylindrical envelope (66 mm × 115 mm, ≤ 310 g); all structural, thermal, and power budgets are documented with positive margins and verified against flight hardware.', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_outcomes (id, period_id, source_outcome_id, code, label, description, sort_order) VALUES ('959f66fc-980f-4ab8-a33c-392d7b75301b', 'c8021bb8-fd12-4826-a314-7139a5971fe5', '7271f0a4-8a94-4f5c-a353-83a5d0ce6b6a', 'CS-2', 'Primary Mission', 'Air pressure and air temperature are sampled at ≥ 1 Hz throughout descent; data is stored on-board and simultaneously downlinked to the ground station; post-flight data completeness exceeds 95 % of expected samples.', 2) ON CONFLICT DO NOTHING;
INSERT INTO period_outcomes (id, period_id, source_outcome_id, code, label, description, sort_order) VALUES ('e372ee99-b629-4df0-aff1-00d904c3c61c', 'c8021bb8-fd12-4826-a314-7139a5971fe5', '7c0d1505-dc43-40f8-acbd-755f79ba4fc8', 'CS-3', 'Secondary Mission', 'Team-defined secondary mission demonstrates scientific or engineering creativity (e.g., imaging, atmospheric sensing, attitude determination); mission objective is novel, clearly scoped, and successfully executed in flight.', 3) ON CONFLICT DO NOTHING;
INSERT INTO period_outcomes (id, period_id, source_outcome_id, code, label, description, sort_order) VALUES ('3ca571a1-ea7c-422a-a29d-e41b2606125c', 'c8021bb8-fd12-4826-a314-7139a5971fe5', 'b39b06a3-3536-48fd-a862-cc82253681f7', 'CS-4', 'Descent & Recovery', 'Passive descent system achieves a terminal velocity between 10 m/s and 15 m/s throughout the altitude range; CanSat is recovered intact with no damage to electronics or structure after landing.', 4) ON CONFLICT DO NOTHING;
