INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('8f488976-2145-48e2-ade4-f716b85b4cc7', '19b42e9e-c170-4eb9-aa61-76b77e79ffbd', 'CS-7', 'Range Safety', 'All range safety rules are followed including pre-flight hardware inspection, parachute deployment verification, launch pad clearance procedures, and post-flight range sweep; no safety violations are recorded by range safety officers.', 7) ON CONFLICT (id) DO UPDATE SET label=EXCLUDED.label, description=EXCLUDED.description;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('d981c6fb-1a20-4c8a-a393-1f4c110c5d5e', '19b42e9e-c170-4eb9-aa61-76b77e79ffbd', 'design_compliance', 'Design Compliance', 'Evaluates adherence to all specified volume, mass, and structural design constraints, with documented margin analysis.', 20, 20, '#6366F1', '[{"min":18,"max":20,"label":"Excellent","description":"All constraints fully met with documented margin analysis."},{"min":14,"max":17,"label":"Good","description":"Constraints met with minor deviations."},{"min":10,"max":13,"label":"Developing","description":"One or more constraints marginally exceeded."},{"min":0,"max":9,"label":"Insufficient","description":"Multiple constraints violated."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('9af78dfa-b6c6-4efc-a78e-ee35674f4789', '19b42e9e-c170-4eb9-aa61-76b77e79ffbd', 'mission_execution', 'Mission & Telemetry', 'Assesses successful execution of primary and secondary mission objectives with continuous and reliable telemetry throughout the flight.', 35, 35, '#EF4444', '[{"min":31,"max":35,"label":"Excellent","description":"Primary and secondary missions fully executed. Continuous telemetry."},{"min":24,"max":30,"label":"Good","description":"Primary mission completed. Minor telemetry gaps."},{"min":17,"max":23,"label":"Developing","description":"Primary mission partially completed."},{"min":0,"max":16,"label":"Insufficient","description":"Mission fails to execute."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('8e35567a-0281-497f-a32b-dd0fe36da4c0', '19b42e9e-c170-4eb9-aa61-76b77e79ffbd', 'data_and_documentation', 'Data Analysis', 'Evaluates depth and appropriateness of post-flight data analysis and the overall quality and completeness of written documentation.', 25, 25, '#3B82F6', '[{"min":22,"max":25,"label":"Excellent","description":"Flight data thoroughly analyzed with appropriate methods."},{"min":17,"max":21,"label":"Good","description":"Data analysis competent. Post-flight report addresses key findings."},{"min":12,"max":16,"label":"Developing","description":"Data presented but analysis shallow."},{"min":0,"max":11,"label":"Insufficient","description":"Raw data dump with no meaningful analysis."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('4e591c50-03f5-4776-afbd-bbd1a89ea0c1', '19b42e9e-c170-4eb9-aa61-76b77e79ffbd', 'safety_and_recovery', 'Safety & Recovery', 'Assesses adherence to all range safety procedures, descent rate control within specification, and successful CanSat recovery.', 20, 20, '#10B981', '[{"min":18,"max":20,"label":"Excellent","description":"Recovered intact. Descent rate within spec. All safety procedures followed."},{"min":14,"max":17,"label":"Good","description":"Recovery successful with minor issues."},{"min":10,"max":13,"label":"Developing","description":"Recovery partial or descent rate deviates."},{"min":0,"max":9,"label":"Insufficient","description":"CanSat lost or damaged."}]', 4) ON CONFLICT DO NOTHING;
INSERT INTO periods (id, organization_id, framework_id, name, season, description, start_date, end_date, is_locked, criteria_name, snapshot_frozen_at, activated_at, closed_at, updated_at) VALUES ('9a492b31-eb25-43de-ab79-82b3c9fc64e1', '2060c696-71f7-4a57-a7c9-d3bcdc9db763', '19b42e9e-c170-4eb9-aa61-76b77e79ffbd', '2027 Season (Draft)', 'Spring', 'CanSat 2027 — Planning Phase', '2027-06-24', '2027-06-26', false, 'MF-D27-R', NULL, NULL, NULL, timestamp '2026-03-15 09:00:00') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('93fcb76b-9827-4720-a1a8-9d65fdbc3055', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'FPGA-Based Real-Time Signal Processing for 5G NR', 1, '[{"name":"Aslı Tezcan","order":1},{"name":"Gürkan Ateş","order":2},{"name":"Zehra Kurt","order":3},{"name":"İlker Durmaz","order":4},{"name":"Tuğçe Can","order":5}]', 'Prof. Turgut Ercan, Dr. Ece Aydoğan', 'TED University, EE, TED University, EE', 'Implements a pipelined OFDM receiver on a Xilinx Zynq FPGA targeting 3GPP Release 17 numerology. Achieves sub-millisecond latency for channel estimation, equalization, and LDPC decoding with measured throughput exceeding 1.2 Gbps.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('46123b99-4f0a-4d61-a870-6ef0f78e371f', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'Low-Power IoT Sensor Network for Smart Agriculture', 2, '[{"name":"Berke Şimşek","order":1},{"name":"Sinem Uslu","order":2},{"name":"Selçuk Taner","order":3},{"name":"Simge Kalkan","order":4},{"name":"Emrah Polat","order":5}]', 'Dr. Ece Aydoğan', 'TED University, EE', 'Deploys a LoRaWAN mesh of custom-designed soil-moisture and microclimate sensors across a 2-hectare test field. The STM32-based nodes achieve 18-month battery life through duty-cycled sampling and adaptive transmission intervals.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('733f9e70-8f7b-47dc-ad72-a604c760696f', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'Autonomous Drone Navigation with LiDAR SLAM', 3, '[{"name":"Nur Akdeniz","order":1},{"name":"Candan Yıldız","order":2},{"name":"Beren Yücel","order":3}]', 'Prof. Cengiz Yalın', 'TED University, EE', 'Integrates a Velodyne Puck LiDAR with an NVIDIA Jetson Orin for real-time 3D SLAM on a custom hexacopter. Tested in GPS-denied indoor warehouse environments with obstacle avoidance and path replanning.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('339948a9-b977-4c51-a1bd-c3dab5e32936', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'GaN Power Amplifier Design for Sub-6 GHz 5G', 4, '[{"name":"Melisa Tuncer","order":1},{"name":"Ulaş Sevinç","order":2},{"name":"Gökhan Kılınç","order":3},{"name":"Efe Güneş","order":4},{"name":"Ceylin Aydoğan","order":5}]', 'Dr. Aylin Seçkin, Prof. Tarık Özmen', 'TED University, EE, TED University, EE', 'Designs and fabricates a two-stage GaN HEMT power amplifier operating at 3.5 GHz with 42 dBm output power and 68% PAE. Doherty topology enables high linearity under modulated 5G NR signals.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('2c01817f-5c28-4899-ab4b-fb741b5f8f9b', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'Biomedical Signal Processing for Sleep Apnea Detection', 5, '[{"name":"Tolga Erim","order":1},{"name":"Selin Akay","order":2},{"name":"Korhan Alkan","order":3}]', 'Prof. Tarık Özmen', 'TED University, EE', 'Develops a wearable single-channel EEG acquisition board paired with a TinyML classifier running on an nRF5340 SoC. Detects obstructive sleep apnea events with 94% sensitivity validated against clinical polysomnography.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('00f25636-269c-4d25-abd5-3cdbc12a31f8', '952dd05e-8ff2-44a7-a13b-9a22958f57fb', 'Wearable ECG Monitor with BLE Connectivity', 1, '[{"name":"Pelin Aydın","order":1},{"name":"Serkan Taşkın","order":2},{"name":"Sinan Koç","order":3},{"name":"Müge Çelik","order":4},{"name":"Nur Akdeniz","order":5}]', 'Prof. Turgut Ercan, Dr. Ece Aydoğan', 'TED University, EE, TED University, EE', 'A compact three-lead ECG acquisition system built around the ADS1293 AFE, streaming data over BLE 5.0 to a companion mobile app for real-time arrhythmia flagging.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('46c52db6-2cd0-404d-a2bf-23d390c741ad', '952dd05e-8ff2-44a7-a13b-9a22958f57fb', 'MIMO Antenna Design for Indoor 5G Coverage', 2, '[{"name":"Büşra Doğan","order":1},{"name":"Oğulcan Demirel","order":2},{"name":"Aslı Tezcan","order":3},{"name":"Baran Tekin","order":4},{"name":"Tuğçe Can","order":5}]', 'Prof. Turgut Ercan', 'TED University, EE', 'Designs a four-element MIMO patch antenna array at 3.5 GHz with envelope correlation below 0.15, targeting small-cell indoor base stations for enhanced spatial multiplexing.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('12cbf2c4-0a16-4574-abb5-b601beec8176', '952dd05e-8ff2-44a7-a13b-9a22958f57fb', 'Solar-Powered Environmental Monitoring Station', 3, '[{"name":"Taylan Ergin","order":1},{"name":"Azra Evren","order":2},{"name":"Esra Kaya","order":3},{"name":"Yaren Uçar","order":4},{"name":"Eylül Özdemir","order":5}]', 'Dr. Ece Aydoğan', 'TED University, EE', 'A self-sustaining weather station combining a 20W solar panel with MPPT charging, measuring temperature, humidity, PM2.5, and UV index with hourly LoRa uploads to a cloud dashboard.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('0af988df-e6d9-4ac1-a6ec-56343146a552', '952dd05e-8ff2-44a7-a13b-9a22958f57fb', 'Robotic Arm Control via EMG Signals', 4, '[{"name":"Alp Sönmez","order":1},{"name":"İlayda Başaran","order":2},{"name":"Nehir Tosun","order":3},{"name":"Ülkü Tuncer","order":4},{"name":"Semih Karataş","order":5}]', 'Dr. Ece Aydoğan, Prof. Cengiz Yalın', 'TED University, EE, TED University, EE', 'Uses surface EMG electrodes and an SVM classifier to map forearm muscle activation patterns to six-DOF robotic arm movements for prosthetic control research.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('9dbf8fbe-1580-489c-a551-1eda5fb69025', '952dd05e-8ff2-44a7-a13b-9a22958f57fb', 'Smart Grid Fault Detection Using Phasor Data', 5, '[{"name":"Betül Sezer","order":1},{"name":"Selin Akay","order":2},{"name":"Görkem Taş","order":3},{"name":"Koray Sert","order":4},{"name":"Beyza Güler","order":5}]', 'Prof. Cengiz Yalın', 'TED University, EE', 'Implements a synchrophasor-based fault detection algorithm on a Raspberry Pi, processing PMU data streams to classify and localize transmission line faults within 40 ms.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('7668ebe3-a6f0-40ef-ad92-05cd2694db44', '952dd05e-8ff2-44a7-a13b-9a22958f57fb', 'Power Line Communication Modem for Smart Metering', 6, '[{"name":"Aslıhan Coşkun","order":1},{"name":"Umutcan Demir","order":2},{"name":"Dila Öztürk","order":3},{"name":"Irmak Genç","order":4},{"name":"Tayfun Aydın","order":5}]', 'Dr. Aylin Seçkin', 'TED University, EE', 'Designs an OFDM-based narrowband PLC modem compliant with ITU-T G.9903, achieving 128 kbps throughput over 500 m of low-voltage distribution cabling.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('85a5fd07-493e-4336-adb4-969cce024854', '952dd05e-8ff2-44a7-a13b-9a22958f57fb', 'Automatic License Plate Recognition with Edge AI', 7, '[{"name":"Sibel Acar","order":1},{"name":"Umut Şahin","order":2},{"name":"Burak Aslan","order":3}]', 'Dr. Aylin Seçkin, Prof. Tarık Özmen', 'TED University, EE, TED University, EE', 'Deploys a YOLOv8-based plate detection and OCR pipeline on a Google Coral Edge TPU, processing 15 fps video with 97% character accuracy under varying lighting conditions.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('e42ee6b2-bd1c-49a7-a92f-70fa22a0c956', '952dd05e-8ff2-44a7-a13b-9a22958f57fb', 'UWB Indoor Positioning for Warehouse Robotics', 8, '[{"name":"Damla Kılıç","order":1},{"name":"Berra Yılmaz","order":2},{"name":"Neslihan Koray","order":3},{"name":"Candan Yıldız","order":4}]', 'Prof. Tarık Özmen', 'TED University, EE', 'Implements a TWR-based UWB positioning system using DW3000 modules, achieving sub-10 cm ranging accuracy to guide autonomous mobile robots in a warehouse testbed.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('9df9b21f-4b06-48ec-a936-4796f1469da7', '952dd05e-8ff2-44a7-a13b-9a22958f57fb', 'Piezoelectric Energy Harvester for Bridge Monitoring', 9, '[{"name":"Ege Duran","order":1},{"name":"Polat Çetin","order":2},{"name":"Ebru Gökçe","order":3}]', 'Prof. Tarık Özmen', 'TED University, EE', 'Harvests vibration energy from traffic-induced bridge oscillations using a PZT bimorph cantilever array, generating sufficient power to drive a wireless strain-gauge sensor node.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('a1428f33-5d50-4922-a7e6-48a56760660d', '952dd05e-8ff2-44a7-a13b-9a22958f57fb', 'Gesture-Controlled Wheelchair with Depth Camera', 10, '[{"name":"Furkan Polat","order":1},{"name":"Tuna Bakır","order":2},{"name":"Dicle Arslan","order":3}]', 'Dr. Seda Bayraktar, Prof. Turgut Ercan', 'TED University, EE, TED University, EE', 'Combines an Intel RealSense D435 depth camera with a CNN gesture classifier to enable hands-free wheelchair navigation for patients with limited upper-body mobility.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('be3a4e6f-a69b-418a-a333-215fbfdf5261', 'e55e0820-93f2-487f-abaa-4ae64a77e93e', 'Visible Light Communication Transceiver Prototype', 1, '[{"name":"Umutcan Demir","order":1},{"name":"Kübra Şen","order":2},{"name":"Ozan Çelebi","order":3},{"name":"Onur Çelik","order":4}]', 'Prof. Turgut Ercan, Dr. Ece Aydoğan', 'TED University, EE, TED University, EE', 'Builds a VLC link using high-brightness LEDs and a silicon photodiode receiver, demonstrating 10 Mbps data transfer with OOK modulation over 2 m line-of-sight.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('85cf466e-cb30-49f6-a3ac-58884c85a854', 'e55e0820-93f2-487f-abaa-4ae64a77e93e', 'FPGA-Based Audio Effects Processor', 2, '[{"name":"Altan Çevik","order":1},{"name":"Ceyda Vural","order":2},{"name":"Tolga Erim","order":3}]', 'Prof. Turgut Ercan', 'TED University, EE', 'Implements real-time reverb, chorus, and parametric EQ on an Altera Cyclone IV FPGA with 24-bit audio I/O and MIDI-controlled parameter switching.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('c2fd33b6-8b39-4397-acec-1dd12cdfc62b', 'e55e0820-93f2-487f-abaa-4ae64a77e93e', 'Quadcopter Stabilization with Kalman Filtering', 3, '[{"name":"Şule Ergün","order":1},{"name":"Çağrı Özkan","order":2},{"name":"Irmak Genç","order":3},{"name":"Baturalp Koç","order":4},{"name":"Nihan Sezer","order":5}]', 'Dr. Ece Aydoğan', 'TED University, EE', 'Fuses accelerometer, gyroscope, and barometer data through an extended Kalman filter for attitude estimation, enabling stable hovering on a custom-built quadcopter frame.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('49d1f760-f4a0-40f3-a142-a11518c59c92', 'e55e0820-93f2-487f-abaa-4ae64a77e93e', 'Thermal Imaging for Predictive Maintenance', 4, '[{"name":"Sena Yücel","order":1},{"name":"Efe Güneş","order":2},{"name":"Melis Kavak","order":3},{"name":"Esra Kaya","order":4},{"name":"Ece Yıldırım","order":5}]', 'Prof. Cengiz Yalın, Dr. Aylin Seçkin', 'TED University, EE, TED University, EE', 'Uses a FLIR Lepton thermal camera module interfaced with an ESP32 to detect overheating components in electrical panels, with threshold-based alerts sent to a web dashboard.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('37454857-5e99-408e-a70c-253d8e140e33', 'e55e0820-93f2-487f-abaa-4ae64a77e93e', 'Bluetooth Mesh Network for Smart Home', 5, '[{"name":"Nisa Öztürk","order":1},{"name":"Serhat Çakır","order":2},{"name":"Berra Yılmaz","order":3},{"name":"Elif Naz Balcı","order":4}]', 'Dr. Aylin Seçkin', 'TED University, EE', 'Creates a BLE Mesh network of smart light switches and sensors using nRF52840 modules, with a central gateway providing app-based control and scheduling.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('038c82cd-2cbd-49c6-a4a5-1f4310dcbf24', 'e55e0820-93f2-487f-abaa-4ae64a77e93e', 'Microstrip Antenna for X-Band Radar', 6, '[{"name":"Tuğba Erdem","order":1},{"name":"Müge Çelik","order":2},{"name":"Erdem Uzun","order":3}]', 'Dr. Aylin Seçkin', 'TED University, EE', 'Designs and fabricates a 4x4 microstrip patch array on Rogers RT/duroid at 10 GHz, achieving 18 dBi gain with sidelobe levels below -20 dB for short-range radar applications.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('0a8aefdb-8daa-4b08-a9da-449b739d60f3', 'e55e0820-93f2-487f-abaa-4ae64a77e93e', 'PID-Controlled Self-Balancing Robot', 7, '[{"name":"Azra Beyaz","order":1},{"name":"Barın Çelik","order":2},{"name":"Volkan Demir","order":3},{"name":"Berk Gündüz","order":4},{"name":"Utku Erdem","order":5}]', 'Prof. Tarık Özmen, Dr. Seda Bayraktar', 'TED University, EE, TED University, EE', 'A two-wheeled inverted pendulum robot using an MPU6050 IMU and a tuned PID controller on an Arduino Mega, capable of maintaining balance on flat and inclined surfaces.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('5368a9f3-4762-44a5-a950-e0ab610b0183', 'e55e0820-93f2-487f-abaa-4ae64a77e93e', 'Low-Cost EMG Board for Rehabilitation', 8, '[{"name":"Sevval Kaplan","order":1},{"name":"Caner Turgut","order":2},{"name":"Kaan Avcı","order":3},{"name":"Burcu Tan","order":4}]', 'Dr. Seda Bayraktar', 'TED University, EE', 'Designs a four-channel surface EMG acquisition board with instrumentation amplifiers and a 12-bit ADC, providing real-time muscle activation feedback for physiotherapy exercises.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('60146fd4-7794-4dd7-a91f-8dad08a9759a', '10078594-2707-4c3f-a212-42add04fbd84', 'DC Motor Speed Control with Fuzzy Logic', 1, '[{"name":"Pelin Aydın","order":1},{"name":"Aslıhan Coşkun","order":2},{"name":"Akın Bulut","order":3}]', 'Prof. Turgut Ercan, Dr. Ece Aydoğan', 'TED University, EE, TED University, EE', 'Implements a Mamdani-type fuzzy logic speed controller for a 24V brushed DC motor, comparing transient response and steady-state error against a conventional PID controller.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('b89cf1e1-6820-4efb-ad3e-9ab5b4f1bafa', '10078594-2707-4c3f-a212-42add04fbd84', 'PCB Design for Portable Oscilloscope', 2, '[{"name":"Tunahan Korkut","order":1},{"name":"Kağan Erdem","order":2},{"name":"Damla Kılıç","order":3},{"name":"Zeynep Gül","order":4}]', 'Dr. Ece Aydoğan', 'TED University, EE', 'Designs a two-channel 20 MHz portable oscilloscope around an STM32H7 MCU with a 12-bit ADC and a 3.5-inch TFT display, powered by a rechargeable LiPo battery.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('0db79881-0974-4a2d-a8a2-86efdb30bda1', '10078594-2707-4c3f-a212-42add04fbd84', 'Home Energy Management Dashboard', 3, '[{"name":"Turgay Keskin","order":1},{"name":"Görkem Taş","order":2},{"name":"Tuğçe Can","order":3},{"name":"Beren Yücel","order":4}]', 'Prof. Cengiz Yalın', 'TED University, EE', 'Monitors household power consumption via non-invasive current clamps connected to an ESP32, displaying real-time and historical usage data on a locally hosted web dashboard.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('94f3c7a2-8ea9-4145-ab65-f3ff259b945c', '10078594-2707-4c3f-a212-42add04fbd84', 'AM Radio Receiver Design and Assembly', 4, '[{"name":"Sibel Acar","order":1},{"name":"Ezgi Doruk","order":2},{"name":"Burak Aslan","order":3}]', 'Dr. Aylin Seçkin, Prof. Tarık Özmen', 'TED University, EE, TED University, EE', 'Constructs a superheterodyne AM receiver covering the 530-1700 kHz band, using discrete transistor stages for RF amplification, mixing, IF filtering, and audio output.') ON CONFLICT DO NOTHING;
