INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('d50def54-dadb-4116-a17c-0f309bbb2e5a', 'f8c01197-da4a-4646-a42d-8dc74715e3bc', 'Interactive Debugger for WebAssembly', 6, '[{"name":"Hazel Foster","order":1},{"name":"Noah Patterson","order":2},{"name":"Lucy Brooks","order":3}]', 'Dr. Karen White', 'Carnegie Mellon, SCS', 'Extends Chrome DevTools to support source-level breakpoints, variable inspection, and call-stack navigation for Wasm modules compiled from C/Rust via DWARF debug info.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('3b8b2e62-bc66-4c8c-ad14-371049c8204e', 'e77bf882-fc32-461c-acab-6ee1696df0c7', 'Otonom Sürü İHA Takip ve Koordinasyon Sistemi', 1, '[{"name":"Nil Akyüz","order":1},{"name":"Nur Akdeniz","order":2},{"name":"Yunus Emre Boz","order":3},{"name":"Pınar Şahin","order":4},{"name":"Batuhan Koçak","order":5}]', 'Prof. Serhat Öztürk, Dr. Fatma Korkmaz', 'İTÜ, Uçak Mühendisliği, ODTÜ, Havacılık', 'Üç adet quadrotor İHA arasında UWB haberleşme ile formasyon uçuşu gerçekleştiren otonom sürü kontrol sistemi. Lider-takipçi algoritması ile GPS-destekli rota planlaması ve engel kaçınma entegrasyonu sağlanmıştır.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('c23aa93d-d7c4-4b82-aee5-2d857b47638c', 'e77bf882-fc32-461c-acab-6ee1696df0c7', 'Yüksek İrtifa Hibrit Roket Motoru Tasarımı', 2, '[{"name":"Taylan Ergin","order":1},{"name":"Gökçen Aksoy","order":2},{"name":"Baran Tekin","order":3},{"name":"Oğuzhan Kara","order":4}]', 'Prof. Serhat Öztürk', 'İTÜ, Uçak Mühendisliği', 'HTPB katı yakıt ve N₂O oksitleyici kullanan hibrit roket motorunun tasarımı, üretimi ve statik ateşleme testleri. Hedef itki profili 500 N olup, yanma odası basıncı ve özgül itki ölçümleri gerçekleştirilmiştir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('1b122688-dc8e-467d-aa9d-16a7c8dbd1a8', 'e77bf882-fc32-461c-acab-6ee1696df0c7', 'Otonom Sualtı Aracı ile Deniz Tabanı Haritalama', 3, '[{"name":"Berke Şimşek","order":1},{"name":"Barış Yıldız","order":2},{"name":"Pelin Aydın","order":3}]', 'Dr. Fatma Korkmaz', 'ODTÜ, Havacılık', 'ROS2 tabanlı otonom sualtı aracı (AUV) ile sonar ve stereo kamera verisi kullanarak deniz tabanı batimetri haritası oluşturma. Dalış derinliği 30 m, navigasyon DVL ve INS füzyonu ile sağlanmıştır.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('c900eb14-5b94-461b-ac3d-f2a9075269b6', 'e77bf882-fc32-461c-acab-6ee1696df0c7', 'VTOL Sabit Kanatlı Kargo Dronu Prototipi', 4, '[{"name":"İlayda Başaran","order":1},{"name":"Defne Çetin","order":2},{"name":"Damla Kılıç","order":3},{"name":"Furkan Polat","order":4},{"name":"Bengisu Işık","order":5}]', 'Dr. Fatma Korkmaz, Prof. Murat Yıldız', 'ODTÜ, Havacılık, İTÜ, Makina Mühendisliği', 'Tilt-rotor mekanizmalı VTOL sabit kanat platformu; 5 kg faydalı yük kapasitesiyle 60 km menzil hedeflenmiştir. Geçiş uçuşu kontrol algoritması Pixhawk 6X üzerinde doğrulanmıştır.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('ba5787ab-8196-4453-afd3-2e47c5185fb8', 'e77bf882-fc32-461c-acab-6ee1696df0c7', 'Radar Absorban Kompozit Kaplama Geliştirme', 5, '[{"name":"Akın Bulut","order":1},{"name":"Tayfun Aydın","order":2},{"name":"Fatih Tezel","order":3},{"name":"Berra Yılmaz","order":4}]', 'Prof. Murat Yıldız', 'İTÜ, Makina Mühendisliği', 'Karbon nanotüp katkılı epoksi reçine ile X-bandı (8-12 GHz) radar absorban malzeme geliştirilmiştir. Ölçüm sonuçları -18 dB yansıma kaybı ile düşük gözlenebilirlik hedefini karşılamaktadır.') ON CONFLICT DO NOTHING;
