INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('202b2597-5a44-4ae0-a6a5-4834870f87d0', '05a1eb4a-d4cf-478b-a52d-578c3d9c22ad', 'Mikroalg Biyoreaktörü ile Atmosferik CO₂ Yakalama', 4, '[{"name":"Haluk Güler","order":1},{"name":"Beyza Güler","order":2},{"name":"Caner Turgut","order":3},{"name":"Mazhar Özdemir","order":4},{"name":"Berk Gündüz","order":5}]', 'Selin Karadeniz, Ahmet Çelik', 'İstanbul Atatürk Fen Lisesi, İzmir Fen Lisesi', 'Chlorella vulgaris mikroalg kültürü barındıran 10 L fotobiyoreaktör ile atmosferik CO₂ yakalama verimliliği ölçülmüştür. LED aydınlatma spektrumu ve pH optimizasyonu ile günlük 2.3 g/L biyokütle üretimi sağlanmıştır.') ON CONFLICT DO NOTHING;
