INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('7c08441a-9b1c-43b1-ab4b-a6d204c8f90d', '6c44b363-4522-4cad-a251-06484b72b164', 'Phased Array Antenna for 28 GHz mmWave 5G', 1, '[{"name":"Tessa Marlow","order":1},{"name":"Beau Garrett","order":2},{"name":"Cedric Rush","order":3},{"name":"Hayes Drummond","order":4},{"name":"Jensen Holt","order":5}]', 'Prof. Harold Kim, Dr. Sarah Novak', 'U. Michigan, ECE, Georgia Tech, ECE', 'A 16-element patch phased array on Rogers RO4003C with corporate feed network and 5-bit digital phase shifters, achieving ±45° beam scanning with 22 dBi peak gain at 28 GHz.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('ca11e01d-82af-4055-aa03-4640780aa91b', '6c44b363-4522-4cad-a251-06484b72b164', 'Wearable UHF RFID Tag Antenna for Patient Tracking', 2, '[{"name":"Julian Hayes","order":1},{"name":"Benjamin Cruz","order":2},{"name":"Harper Morgan","order":3}]', 'Prof. Harold Kim', 'U. Michigan, ECE', 'A flexible dipole-based RFID tag antenna printed on Kapton substrate, designed to operate on the human body at 915 MHz with a read range exceeding 5 m despite body-loading effects.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('f587f2b0-2c8e-40bc-ac05-182f1d07cf58', '6c44b363-4522-4cad-a251-06484b72b164', 'Dual-Band Circularly Polarized Patch for GPS/GLONASS', 3, '[{"name":"Layla Stone","order":1},{"name":"Esme Darling","order":2},{"name":"Lena Fairchild","order":3},{"name":"Mabel Trent","order":4}]', 'Prof. Harold Kim', 'U. Michigan, ECE', 'A stacked patch antenna providing RHCP at L1 (1575 MHz) and L2 (1227 MHz) with axial ratio below 2 dB across both bands, intended for precision agriculture GNSS receivers.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('32f1ec66-89dc-49f5-a867-7ec816ff6d07', '6c44b363-4522-4cad-a251-06484b72b164', 'Metamaterial Absorber for Radar Cross-Section Reduction', 4, '[{"name":"Ada Carrington","order":1},{"name":"Selene Ashford","order":2},{"name":"Isla Webb","order":3}]', 'Dr. Sarah Novak, Prof. Wei Zhang', 'Georgia Tech, ECE, UCLA, EE', 'A polarization-insensitive metamaterial absorber using resistively loaded split-ring resonators, achieving greater than 90% absorption from 8 to 12 GHz for RCS reduction applications.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('5e784ee9-8ce7-4cae-a580-a07a1f11b557', '6c44b363-4522-4cad-a251-06484b72b164', 'Reconfigurable Metasurface for Beam Steering', 5, '[{"name":"Logan Bailey","order":1},{"name":"Alina Frost","order":2},{"name":"Gemma Whitlock","order":3},{"name":"Dahlia Novak","order":4},{"name":"Dylan Reed","order":5}]', 'Dr. Sarah Novak', 'Georgia Tech, ECE', 'A 1-bit reconfigurable intelligent surface with PIN-diode-switched unit cells at 5.8 GHz, electronically steering a reflected beam over ±60° with measured 1.5 dB scanning loss.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('acb58410-579f-4a67-a462-68dfd1beec2e', '6c44b363-4522-4cad-a251-06484b72b164', 'Textile-Integrated Antenna Array for Body Area Networks', 6, '[{"name":"Liam Fletcher","order":1},{"name":"Samuel Rivera","order":2},{"name":"Sophie Clarke","order":3},{"name":"Cassidy Wren","order":4},{"name":"Mia Howard","order":5}]', 'Prof. Wei Zhang', 'UCLA, EE', 'A two-element conductive-thread antenna array embroidered into a polyester sports shirt, operating at 2.45 GHz for WBAN with -15 dB mutual coupling despite close inter-element spacing.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('32635f22-7ece-4fe8-a2e5-a0596659e09a', '6c44b363-4522-4cad-a251-06484b72b164', 'Frequency-Tunable Slot Antenna Using Varactor Diodes', 7, '[{"name":"Harlow Sinclair","order":1},{"name":"Tessa Rowan","order":2},{"name":"Ruby Murphy","order":3}]', 'Prof. Wei Zhang, Dr. Anita Patel', 'UCLA, EE, Purdue, ECE', 'A CPW-fed slot antenna whose resonant frequency tunes continuously from 2.2 to 3.8 GHz via reverse-biased varactor loading, covering LTE bands 1 through 7 with a single aperture.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('07acad75-3870-4cca-a9e6-90ebcae9aa69', '6c44b363-4522-4cad-a251-06484b72b164', 'SIW-Based Diplexer for TX-RX Systems', 8, '[{"name":"Sophia Linden","order":1},{"name":"Holden Sharpe","order":2},{"name":"Callum Harding","order":3},{"name":"Beckett Thorne","order":4},{"name":"Rosalie Grant","order":5}]', 'Prof. Wei Zhang', 'UCLA, EE', 'A substrate-integrated-waveguide diplexer at 24/28 GHz for full-duplex mmWave front-ends, fabricated on a single Rogers 5880 layer with better than 35 dB TX-RX isolation.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('ee36879d-c1a0-4042-ae3d-4785e41a000b', '6c44b363-4522-4cad-a251-06484b72b164', 'Millimeter-Wave Lens Antenna for Automotive Radar', 9, '[{"name":"Royce Hendrix","order":1},{"name":"Aria Sanders","order":2},{"name":"Aurora Price","order":3}]', 'Dr. Anita Patel', 'Purdue, ECE', 'A 3D-printed dielectric lens with gradient-index profile illuminated by an open-ended waveguide at 77 GHz, producing a 3° pencil beam with 28 dBi gain for long-range automotive radar.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('40a4601a-bd4f-420e-ad80-b3567e6178b3', '6c44b363-4522-4cad-a251-06484b72b164', 'Fractal Antenna for Ultra-Wideband Applications', 10, '[{"name":"June Holbrook","order":1},{"name":"Zoe Powell","order":2},{"name":"Reid Calloway","order":3},{"name":"Connor Ross","order":4},{"name":"Nathan Cox","order":5}]', 'Dr. Anita Patel, Prof. Gregory Harmon', 'Purdue, ECE, Ohio State, ECE', 'A Minkowski-island fractal monopole printed on FR-4, covering 3.1 to 10.6 GHz with VSWR below 2:1 and a compact footprint 40% smaller than a conventional UWB disc monopole.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('558f6b14-f11f-4dc3-ad37-c9041ad4e145', '318124ea-8614-4355-ad48-2486524dfc13', 'Reconfigurable FSS for 5G Shielding', 1, '[{"name":"Eleanor Marsh","order":1},{"name":"Nathan Cox","order":2},{"name":"Eva Harding","order":3}]', 'Prof. Harold Kim, Dr. Sarah Novak', 'U. Michigan, ECE, Georgia Tech, ECE', 'A frequency-selective surface with PIN-diode-switchable unit cells that toggles between pass and stop states at 3.5 GHz, enabling on-demand electromagnetic shielding for secure rooms.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('e970c78e-aaff-43ef-a236-77caf54b07ce', '318124ea-8614-4355-ad48-2486524dfc13', 'Compact MIMO Antenna for Sub-6 GHz Handsets', 2, '[{"name":"Freya Langston","order":1},{"name":"Daniel Frost","order":2},{"name":"Mia Howard","order":3},{"name":"Grace Kelly","order":4}]', 'Prof. Harold Kim', 'U. Michigan, ECE', 'A four-port MIMO antenna occupying 150x75 mm using orthogonal slot modes to achieve ECC below 0.05 across 3.3-3.8 GHz for 5G smartphone integration.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('9c450cf6-cae4-4390-a3ed-12f231962d02', '318124ea-8614-4355-ad48-2486524dfc13', 'SIW Filter for Ka-Band', 3, '[{"name":"Clarity Vane","order":1},{"name":"Dominic Hurst","order":2},{"name":"Wyatt Watson","order":3},{"name":"Sophie Clarke","order":4}]', 'Dr. Sarah Novak', 'Georgia Tech, ECE', 'A fourth-order Chebyshev bandpass filter implemented in SIW at 26 GHz with 800 MHz bandwidth, 1.2 dB insertion loss, and 25 dB rejection at ±1.5 GHz offset.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('985b9ce9-1302-4ed5-ac37-74f7c3eebfc5', '318124ea-8614-4355-ad48-2486524dfc13', 'Broadband Log-Periodic for EMC Testing', 4, '[{"name":"Keaton Voss","order":1},{"name":"Abigail Reeves","order":2},{"name":"Aurora Price","order":3}]', 'Dr. Sarah Novak, Prof. Wei Zhang', 'Georgia Tech, ECE, UCLA, EE', 'A printed log-periodic dipole array covering 200 MHz to 6 GHz for pre-compliance EMC measurements, with calibrated gain data traceable to a reference horn antenna.') ON CONFLICT DO NOTHING;
