INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('fc0404be-5d8b-4521-a139-40d70ba3fcc4', '318124ea-8614-4355-ad48-2486524dfc13', 'Circularly Polarized Horn for Satellite Comm', 6, '[{"name":"Faye Alderman","order":1},{"name":"Elias Boyd","order":2},{"name":"Iris Mercer","order":3},{"name":"Emma Peterson","order":4}]', 'Prof. Wei Zhang', 'UCLA, EE', 'A corrugated conical horn antenna with septum polarizer producing RHCP at Ku-band (12.5 GHz) with 0.5 dB axial ratio and 20 dBi gain for VSAT ground terminals.') ON CONFLICT DO NOTHING;
