('a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'aaa0da50-6432-47e0-ab48-b01ca823ef19', 4, NULL, false, (timestamp '2026-04-21 09:00:00' + interval '5 hours 51 minutes')),
('a0d6f60d-ece4-40f8-aca2-955b4abc5d88', '9a21397b-552a-4b00-a5c4-15a0982436b1', 5, 'Very practical system. We completed all evaluations on poster day without any issues.', true, (timestamp '2026-04-21 09:00:00' + interval '12 hours 26 minutes')),
