  framework_criteria,
  framework_outcomes,
  frameworks,
  admin_user_sessions,
  memberships,
  org_applications,
  organizations,
  profiles
CASCADE;

DELETE FROM auth.identities WHERE user_id IN (SELECT id FROM auth.users WHERE email != 'demo.admin@vera-eval.app');
DELETE FROM auth.users WHERE email != 'demo.admin@vera-eval.app';
UPDATE security_policy SET policy = policy
  || '{"maxPinAttempts":3,"pinLockCooldown":"5m","qrTtl":"24h"}'::jsonb
  WHERE id = 1;

